#![forbid(unsafe_code)]
// RNN utils, init functions, and module implementations
use std::collections::BTreeMap;

use ft_api::FrankenTorchSession;
use ft_autograd::{AutogradError, FunctionCtx, TensorNodeId};
use ft_core::{DType, DenseTensor, DenseTensorError, Device};
use ft_dispatch::{DispatchError, DispatchKeyError};

fn incompatible_error(reason: &'static str) -> AutogradError {
    AutogradError::Dispatch(DispatchError::Key(DispatchKeyError::IncompatibleSet {
        reason,
    }))
}

fn overflow_error(reason: &'static str) -> AutogradError {
    incompatible_error(reason)
}

fn validate_dropout_probability(dropout: f64, reason: &'static str) -> Result<(), AutogradError> {
    if !dropout.is_finite() || !(0.0..=1.0).contains(&dropout) {
        return Err(incompatible_error(reason));
    }
    Ok(())
}

fn validate_positive_pooling_dims(
    dims: &[usize],
    reason: &'static str,
) -> Result<(), AutogradError> {
    if dims.contains(&0) {
        return Err(incompatible_error(reason));
    }
    Ok(())
}

fn validate_positive_finite(value: f64, reason: &'static str) -> Result<(), AutogradError> {
    if !value.is_finite() || value <= 0.0 {
        return Err(incompatible_error(reason));
    }
    Ok(())
}

fn checked_mul(a: usize, b: usize, reason: &'static str) -> Result<usize, AutogradError> {
    a.checked_mul(b).ok_or(overflow_error(reason))
}

fn checked_add(a: usize, b: usize, reason: &'static str) -> Result<usize, AutogradError> {
    a.checked_add(b).ok_or(overflow_error(reason))
}

#[derive(Clone, Copy)]
struct ConvTransposeOutputDimReasons {
    overflow_reason: &'static str,
    padding_overflow_reason: &'static str,
    underflow_reason: &'static str,
    empty_reason: &'static str,
}

fn checked_conv_transpose_output_dim(
    input: usize,
    stride: usize,
    kernel: usize,
    padding: usize,
    output_padding: usize,
    reasons: ConvTransposeOutputDimReasons,
) -> Result<usize, AutogradError> {
    if input == 0 {
        return Err(incompatible_error(reasons.empty_reason));
    }
    let span = checked_mul(input - 1, stride, reasons.overflow_reason)?;
    let base = checked_add(span, kernel, reasons.overflow_reason)?;
    let base = checked_add(base, output_padding, reasons.overflow_reason)?;
    let padding = checked_mul(padding, 2, reasons.padding_overflow_reason)?;
    if base <= padding {
        return Err(incompatible_error(reasons.underflow_reason));
    }
    Ok(base - padding)
}

fn checked_shape_numel(shape: &[usize], reason: &'static str) -> Result<usize, AutogradError> {
    if shape.is_empty() {
        return Ok(1);
    }
    let mut product = 1usize;
    for &dim in shape {
        if dim == 0 {
            return Ok(0);
        }
        product = checked_mul(product, dim, reason)?;
    }
    Ok(product)
}

fn checked_ceil_div(
    numerator: usize,
    denominator: usize,
    reason: &'static str,
) -> Result<usize, AutogradError> {
    if denominator == 0 {
        return Err(incompatible_error("adaptive pool output size must be > 0"));
    }

    let quotient = numerator / denominator;
    if numerator.is_multiple_of(denominator) {
        Ok(quotient)
    } else {
        checked_add(quotient, 1, reason)
    }
}

fn adaptive_pool_start_index(
    output_index: usize,
    input_size: usize,
    output_size: usize,
    reason: &'static str,
) -> Result<usize, AutogradError> {
    Ok(checked_mul(output_index, input_size, reason)? / output_size)
}

fn adaptive_pool_end_index(
    output_index_next: usize,
    input_size: usize,
    output_size: usize,
    multiply_reason: &'static str,
    ceil_reason: &'static str,
) -> Result<usize, AutogradError> {
    let numerator = checked_mul(output_index_next, input_size, multiply_reason)?;
    checked_ceil_div(numerator, output_size, ceil_reason)
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ModuleRegistrationError {
    InvalidName {
        kind: &'static str,
    },
    NameConflict {
        name: String,
    },
    Unsupported {
        module_type: &'static str,
        operation: &'static str,
    },
}

impl std::fmt::Display for ModuleRegistrationError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::InvalidName { kind } => write!(f, "invalid {kind} registration name"),
            Self::NameConflict { name } => {
                write!(
                    f,
                    "registration name '{name}' conflicts with existing state"
                )
            }
            Self::Unsupported {
                module_type,
                operation,
            } => {
                write!(f, "{module_type} does not support '{operation}'")
            }
        }
    }
}

impl std::error::Error for ModuleRegistrationError {}

pub type StateDict = BTreeMap<String, DenseTensor>;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LoadStateDictReport {
    pub missing_keys: Vec<String>,
    pub unexpected_keys: Vec<String>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum StateDictError {
    Autograd(AutogradError),
    DenseTensor(DenseTensorError),
    DuplicateStateKey {
        key: String,
    },
    UnsupportedDType {
        key: String,
        dtype: DType,
    },
    StrictKeyMismatch {
        missing_keys: Vec<String>,
        unexpected_keys: Vec<String>,
    },
    ShapeMismatch {
        key: String,
        expected: Vec<usize>,
        found: Vec<usize>,
    },
    DTypeMismatch {
        key: String,
        expected: DType,
        found: DType,
    },
}

impl std::fmt::Display for StateDictError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Autograd(error) => write!(f, "autograd error: {error}"),
            Self::DenseTensor(error) => write!(f, "dense tensor error: {error}"),
            Self::DuplicateStateKey { key } => write!(f, "duplicate state key '{key}'"),
            Self::UnsupportedDType { key, dtype } => {
                write!(f, "state key '{key}' uses unsupported dtype {dtype:?}")
            }
            Self::StrictKeyMismatch {
                missing_keys,
                unexpected_keys,
            } => write!(
                f,
                "strict load_state_dict key mismatch: missing={missing_keys:?}, unexpected={unexpected_keys:?}"
            ),
            Self::ShapeMismatch {
                key,
                expected,
                found,
            } => write!(
                f,
                "shape mismatch for state key '{key}': expected={expected:?}, found={found:?}"
            ),
            Self::DTypeMismatch {
                key,
                expected,
                found,
            } => write!(
                f,
                "dtype mismatch for state key '{key}': expected={expected:?}, found={found:?}"
            ),
        }
    }
}

impl std::error::Error for StateDictError {}

impl From<AutogradError> for StateDictError {
    fn from(value: AutogradError) -> Self {
        Self::Autograd(value)
    }
}

impl From<DenseTensorError> for StateDictError {
    fn from(value: DenseTensorError) -> Self {
        Self::DenseTensor(value)
    }
}

fn gradient_utils_error(reason: &'static str) -> AutogradError {
    AutogradError::Dispatch(DispatchError::Key(DispatchKeyError::IncompatibleSet {
        reason,
    }))
}

#[derive(Debug, Clone)]
struct RegisteredParameter {
    name: String,
    tensor: Option<TensorNodeId>,
}

#[derive(Debug, Clone)]
struct RegisteredBuffer {
    name: String,
    tensor: Option<TensorNodeId>,
    persistent: bool,
}

fn is_valid_registration_name(name: &str) -> bool {
    if name.is_empty() || name.starts_with('.') || name.ends_with('.') {
        return false;
    }
    name.split('.')
        .all(|part| !part.is_empty() && part.chars().all(|c| c == '_' || c.is_ascii_alphanumeric()))
}

fn upsert_registered_parameter(
    parameters: &mut Vec<RegisteredParameter>,
    name: &str,
    tensor: Option<TensorNodeId>,
) {
    if let Some(existing) = parameters.iter_mut().find(|entry| entry.name == name) {
        existing.tensor = tensor;
    } else {
        parameters.push(RegisteredParameter {
            name: name.to_string(),
            tensor,
        });
    }
}

fn upsert_registered_buffer(
    buffers: &mut Vec<RegisteredBuffer>,
    name: &str,
    tensor: Option<TensorNodeId>,
    persistent: bool,
) {
    if let Some(existing) = buffers.iter_mut().find(|entry| entry.name == name) {
        existing.tensor = tensor;
        existing.persistent = persistent;
    } else {
        buffers.push(RegisteredBuffer {
            name: name.to_string(),
            tensor,
            persistent,
        });
    }
}

/// Trait for neural network modules.
///
/// Modules encapsulate parameters and define a forward computation.
pub trait Module {
    /// Execute the forward pass, returning the output node.
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError>;

    /// Collect all trainable parameter node IDs.
    fn parameters(&self) -> Vec<TensorNodeId>;

    /// Return this module's own named parameters without recursing into children.
    ///
    /// # Default behavior
    /// Returns an empty vector. This is correct for leaf modules that do not own
    /// trainable parameters directly because there is no local parameter state to
    /// expose at this layer.
    ///
    /// # When to override
    /// Override this method when your module owns fixed, statically named parameters.
    /// For example, `Linear` overrides this to return its `weight` and optional `bias`
    /// tensors, while containers such as `Sequential` keep the default and delegate
    /// parameter traversal to their children.
    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        Vec::new()
    }

    /// Return dynamically-registered own parameter slots, including empty registrations.
    ///
    /// # Default behavior
    /// Returns an empty vector. This is correct for modules that do not support
    /// runtime parameter registration because they have no dynamic parameter namespace
    /// to report.
    ///
    /// # When to override
    /// Override this method when your module accepts named parameter registrations that
    /// may or may not currently hold a tensor. For example, modules with optional or
    /// user-supplied parameter slots should return `(name, Option<TensorNodeId>)` pairs
    /// so state traversal can preserve the registration shape even when a slot is empty.
    fn named_parameter_slots_own(&self) -> Vec<(String, Option<TensorNodeId>)> {
        Vec::new()
    }

    /// Return own registered buffers together with persistence metadata.
    ///
    /// # Default behavior
    /// Returns an empty vector. This is correct for modules that do not maintain
    /// buffer state because there are no local non-parameter tensors to serialize
    /// or restore.
    ///
    /// # When to override
    /// Override this method when your module owns registered buffers such as running
    /// statistics, caches, or optional state tensors. For example, normalization
    /// layers override this to surface running moments and persistence flags during
    /// state-dict traversal.
    fn named_buffer_slots_own(&self) -> Vec<(String, Option<TensorNodeId>, bool)> {
        Vec::new()
    }

    /// Register or replace a named parameter slot on this module.
    ///
    /// # Default behavior
    /// Returns `ModuleRegistrationError::Unsupported` with the module type and operation
    /// name. This is correct for modules whose parameter layout is fixed at construction
    /// time because accepting arbitrary registrations would create unreachable state.
    ///
    /// # When to override
    /// Override this method when your module intentionally supports runtime parameter
    /// registration. For example, modules that manage user-extensible state dictionaries
    /// should validate names, update their slot tables, and preserve deterministic
    /// traversal order.
    fn register_parameter(
        &mut self,
        _name: &str,
        _parameter: Option<TensorNodeId>,
    ) -> Result<(), ModuleRegistrationError> {
        Err(ModuleRegistrationError::Unsupported {
            module_type: std::any::type_name::<Self>(),
            operation: "register_parameter",
        })
    }

    /// Register or replace a named buffer slot on this module.
    ///
    /// # Default behavior
    /// Returns `ModuleRegistrationError::Unsupported` with the module type and operation
    /// name. This is correct for modules whose buffer inventory is fixed because the
    /// base trait cannot infer safe persistence or replacement rules for arbitrary names.
    ///
    /// # When to override
    /// Override this method when your module supports runtime buffer registration. For
    /// example, stateful normalization or caching modules should implement this to
    /// validate names, store the optional tensor, and record whether the buffer is
    /// persistent in the state dict.
    fn register_buffer(
        &mut self,
        _name: &str,
        _tensor: Option<TensorNodeId>,
        _persistent: bool,
    ) -> Result<(), ModuleRegistrationError> {
        Err(ModuleRegistrationError::Unsupported {
            module_type: std::any::type_name::<Self>(),
            operation: "register_buffer",
        })
    }

    /// Return direct child sub-modules together with their local names.
    ///
    /// # Default behavior
    /// Returns an empty vector. This is correct for leaf modules because they do not
    /// contain nested sub-modules that need recursive traversal for parameters, buffers,
    /// or mode propagation.
    ///
    /// # When to override
    /// Override this method when your module is a container or composite over other
    /// modules. For example, `Sequential` returns indexed children like `"0"` and `"1"`,
    /// while composite modules such as `MultiheadAttention` return field names like
    /// `"q_proj"` so recursive walks remain deterministic.
    fn named_children(&self) -> Vec<(String, &dyn Module)> {
        Vec::new()
    }

    /// Set training mode for this module and descendants.
    ///
    /// Default behavior recursively propagates to children.
    fn train(&self, mode: bool) {
        for (_, child) in self.named_children() {
            child.train(mode);
        }
    }

    /// Convenience helper to switch into evaluation mode.
    fn eval(&self) {
        self.train(false);
    }

    /// Returns whether this module is in training mode.
    ///
    /// Default behavior returns true for leaf modules and requires all children
    /// to report training mode for container modules.
    fn is_training(&self) -> bool {
        let children = self.named_children();
        children.is_empty() || children.iter().all(|(_, child)| child.is_training())
    }

    /// Export trainable parameters and persistent buffers in a deterministic key order.
    fn state_dict(&self, session: &FrankenTorchSession) -> Result<StateDict, StateDictError>
    where
        Self: Sized,
    {
        module_state_dict(self, session)
    }

    /// Load trainable parameters and persistent buffers from a state dict.
    ///
    /// If `strict` is true, missing/unexpected keys cause an error and no updates are applied.
    fn load_state_dict(
        &self,
        session: &mut FrankenTorchSession,
        state: &StateDict,
        strict: bool,
    ) -> Result<LoadStateDictReport, StateDictError>
    where
        Self: Sized,
    {
        module_load_state_dict(self, session, state, strict)
    }
}

/// Collect direct child modules without names.
pub fn children(module: &dyn Module) -> Vec<&dyn Module> {
    module
        .named_children()
        .into_iter()
        .map(|(_, m)| m)
        .collect()
}

/// Recursively collect all named parameters with hierarchical dot-separated prefixes.
///
/// Pass an empty string for `prefix` to get unqualified names from the root.
/// This matches PyTorch's `module.named_parameters()` behavior: own parameters
/// first, then children's parameters in registration order.
pub fn named_parameters(module: &dyn Module, prefix: &str) -> Vec<(String, TensorNodeId)> {
    let mut result = Vec::new();
    for (name, id) in module.named_parameters_own() {
        let full = if prefix.is_empty() {
            name.to_string()
        } else {
            format!("{prefix}.{name}")
        };
        result.push((full, id));
    }
    for (name, maybe_id) in module.named_parameter_slots_own() {
        if let Some(id) = maybe_id {
            let full = if prefix.is_empty() {
                name
            } else {
                format!("{prefix}.{name}")
            };
            result.push((full, id));
        }
    }
    for (child_name, child) in module.named_children() {
        let child_prefix = if prefix.is_empty() {
            child_name
        } else {
            format!("{prefix}.{child_name}")
        };
        result.extend(named_parameters(child, &child_prefix));
    }
    result
}

/// Recursively collect all sub-modules depth-first, including the root.
///
/// Pass an empty string for `prefix` to get unqualified names from the root.
/// The root module is included with the given prefix (empty string for root).
/// Ordering matches PyTorch's `module.named_modules()` depth-first traversal.
pub fn named_modules<'a>(module: &'a dyn Module, prefix: &str) -> Vec<(String, &'a dyn Module)> {
    let mut result = vec![(prefix.to_string(), module)];
    for (child_name, child) in module.named_children() {
        let child_prefix = if prefix.is_empty() {
            child_name
        } else {
            format!("{prefix}.{child_name}")
        };
        result.extend(named_modules(child, &child_prefix));
    }
    result
}

/// Collect all sub-modules recursively without names.
pub fn modules(module: &dyn Module) -> Vec<&dyn Module> {
    named_modules(module, "")
        .into_iter()
        .map(|(_, m)| m)
        .collect()
}

/// Recursively collect all buffer tensors (including non-persistent buffers).
pub fn named_buffers(module: &dyn Module, prefix: &str) -> Vec<(String, TensorNodeId)> {
    let mut result = Vec::new();
    for (name, maybe_id, _persistent) in module.named_buffer_slots_own() {
        if let Some(id) = maybe_id {
            let full = if prefix.is_empty() {
                name
            } else {
                format!("{prefix}.{name}")
            };
            result.push((full, id));
        }
    }
    for (child_name, child) in module.named_children() {
        let child_prefix = if prefix.is_empty() {
            child_name
        } else {
            format!("{prefix}.{child_name}")
        };
        result.extend(named_buffers(child, &child_prefix));
    }
    result
}

/// Recursively collect all persistent buffer tensors.
pub fn named_persistent_buffers(module: &dyn Module, prefix: &str) -> Vec<(String, TensorNodeId)> {
    let mut result = Vec::new();
    for (name, maybe_id, persistent) in module.named_buffer_slots_own() {
        if persistent && let Some(id) = maybe_id {
            let full = if prefix.is_empty() {
                name
            } else {
                format!("{prefix}.{name}")
            };
            result.push((full, id));
        }
    }
    for (child_name, child) in module.named_children() {
        let child_prefix = if prefix.is_empty() {
            child_name
        } else {
            format!("{prefix}.{child_name}")
        };
        result.extend(named_persistent_buffers(child, &child_prefix));
    }
    result
}

/// Collect all buffer tensors without names (including non-persistent buffers).
pub fn buffers(module: &dyn Module) -> Vec<TensorNodeId> {
    named_buffers(module, "")
        .into_iter()
        .map(|(_, id)| id)
        .collect()
}

fn collect_state_targets(
    module: &dyn Module,
) -> Result<Vec<(String, TensorNodeId)>, StateDictError> {
    let mut targets = Vec::new();
    for (name, id) in named_parameters(module, "") {
        targets.push((name, id));
    }
    for (name, id) in named_persistent_buffers(module, "") {
        targets.push((name, id));
    }

    let mut seen = std::collections::BTreeSet::new();
    for (name, _) in &targets {
        if !seen.insert(name.clone()) {
            return Err(StateDictError::DuplicateStateKey { key: name.clone() });
        }
    }
    Ok(targets)
}

fn snapshot_tensor_for_state_dict(
    session: &FrankenTorchSession,
    key: &str,
    node: TensorNodeId,
) -> Result<DenseTensor, StateDictError> {
    let (values_f64, meta) = session.tensor_values_meta(node)?;
    match meta.dtype() {
        DType::F64 => DenseTensor::from_storage(meta, values_f64).map_err(StateDictError::from),
        DType::F32 => {
            let values_f32 = session.tensor_values_f32(node)?;
            DenseTensor::from_storage_f32(meta, values_f32).map_err(StateDictError::from)
        }
        other => Err(StateDictError::UnsupportedDType {
            key: key.to_string(),
            dtype: other,
        }),
    }
}

pub fn module_state_dict(
    module: &dyn Module,
    session: &FrankenTorchSession,
) -> Result<StateDict, StateDictError> {
    let targets = collect_state_targets(module)?;
    let mut state = StateDict::new();
    for (name, node) in targets {
        let snapshot = snapshot_tensor_for_state_dict(session, name.as_str(), node)?;
        if state.insert(name.clone(), snapshot).is_some() {
            return Err(StateDictError::DuplicateStateKey { key: name });
        }
    }
    Ok(state)
}

pub fn module_load_state_dict(
    module: &dyn Module,
    session: &mut FrankenTorchSession,
    state: &StateDict,
    strict: bool,
) -> Result<LoadStateDictReport, StateDictError> {
    let targets = collect_state_targets(module)?;
    let mut target_map: BTreeMap<String, TensorNodeId> = BTreeMap::new();
    for (name, node) in targets {
        if target_map.insert(name.clone(), node).is_some() {
            return Err(StateDictError::DuplicateStateKey { key: name });
        }
    }

    let mut missing_keys = Vec::new();
    for key in target_map.keys() {
        if !state.contains_key(key) {
            missing_keys.push(key.clone());
        }
    }
    let mut unexpected_keys = Vec::new();
    for key in state.keys() {
        if !target_map.contains_key(key) {
            unexpected_keys.push(key.clone());
        }
    }

    if strict && (!missing_keys.is_empty() || !unexpected_keys.is_empty()) {
        return Err(StateDictError::StrictKeyMismatch {
            missing_keys,
            unexpected_keys,
        });
    }

    // Validate all matching entries first so updates are all-or-nothing.
    let mut updates: Vec<(TensorNodeId, DenseTensor)> = Vec::new();
    for (name, target_node) in &target_map {
        let Some(source_tensor) = state.get(name) else {
            continue;
        };
        let (_, target_meta) = session.tensor_values_meta(*target_node)?;
        let source_meta = source_tensor.meta();
        if target_meta.shape() != source_meta.shape() {
            return Err(StateDictError::ShapeMismatch {
                key: name.clone(),
                expected: target_meta.shape().to_vec(),
                found: source_meta.shape().to_vec(),
            });
        }
        if target_meta.dtype() != source_meta.dtype() {
            return Err(StateDictError::DTypeMismatch {
                key: name.clone(),
                expected: target_meta.dtype(),
                found: source_meta.dtype(),
            });
        }
        updates.push((*target_node, source_tensor.clone()));
    }

    session.no_grad_enter();
    for (target_node, source_tensor) in updates {
        let source_node = session.tensor_variable_from_storage(source_tensor, false);
        session.tensor_zero_(target_node)?;
        session.tensor_add_(target_node, source_node)?;
    }
    session.no_grad_exit();

    Ok(LoadStateDictReport {
        missing_keys,
        unexpected_keys,
    })
}

/// Clip accumulated gradients by total p-norm and return the pre-clip norm.
pub fn clip_grad_norm_(
    session: &mut FrankenTorchSession,
    parameters: &[TensorNodeId],
    max_norm: f64,
    norm_type: f64,
) -> Result<f64, AutogradError> {
    if !max_norm.is_finite() || max_norm < 0.0 {
        return Err(gradient_utils_error(
            "clip_grad_norm_ requires finite non-negative max_norm",
        ));
    }
    if !(norm_type.is_infinite() || (norm_type.is_finite() && norm_type > 0.0)) {
        return Err(gradient_utils_error(
            "clip_grad_norm_ requires positive finite norm_type or +inf",
        ));
    }

    let mut grads = Vec::new();
    for &param in parameters {
        if let Some(grad) = session.tensor_accumulated_gradient(param)? {
            grads.push((param, grad));
        }
    }
    if grads.is_empty() {
        return Ok(0.0);
    }

    let total_norm = if norm_type.is_infinite() {
        grads
            .iter()
            .flat_map(|(_, grad)| grad.iter())
            .map(|value| value.abs())
            .fold(0.0, f64::max)
    } else {
        let norm_acc: f64 = grads
            .iter()
            .flat_map(|(_, grad)| grad.iter())
            .map(|value| value.abs().powf(norm_type))
            .sum();
        norm_acc.powf(1.0 / norm_type)
    };

    if total_norm > max_norm && total_norm > 0.0 {
        let scale = if max_norm == 0.0 {
            0.0
        } else {
            max_norm / total_norm
        };
        for (param, mut grad) in grads {
            for value in &mut grad {
                *value *= scale;
            }
            session.tensor_set_accumulated_gradient(param, grad)?;
        }
    }

    Ok(total_norm)
}

/// Clip accumulated gradients element-wise into `[-clip_value, clip_value]`.
pub fn clip_grad_value_(
    session: &mut FrankenTorchSession,
    parameters: &[TensorNodeId],
    clip_value: f64,
) -> Result<(), AutogradError> {
    if !clip_value.is_finite() || clip_value < 0.0 {
        return Err(gradient_utils_error(
            "clip_grad_value_ requires finite non-negative clip_value",
        ));
    }
    for &param in parameters {
        let Some(mut grad) = session.tensor_accumulated_gradient(param)? else {
            continue;
        };
        for value in &mut grad {
            *value = value.clamp(-clip_value, clip_value);
        }
        session.tensor_set_accumulated_gradient(param, grad)?;
    }
    Ok(())
}

/// Flatten parameters into a single 1D tensor.
pub fn parameters_to_vector(
    session: &mut FrankenTorchSession,
    parameters: &[TensorNodeId],
) -> Result<TensorNodeId, AutogradError> {
    let mut flattened = Vec::new();
    for &parameter in parameters {
        let shape = session.tensor_shape(parameter)?;
        let mut numel = 1usize;
        for dim in shape {
            if dim == 0 {
                numel = 0;
                break;
            }
            numel = numel
                .checked_mul(dim)
                .ok_or_else(|| gradient_utils_error("parameters_to_vector shape overflow"))?;
        }
        if numel == 0 {
            continue;
        }
        flattened.push(session.tensor_reshape(parameter, vec![numel])?);
    }
    match flattened.as_slice() {
        [] => session.tensor_variable(Vec::new(), vec![0], false),
        [single] => Ok(*single),
        _ => session.tensor_cat(&flattened, 0),
    }
}

/// Copy values from a flat 1D tensor back into parameter tensors.
pub fn vector_to_parameters(
    session: &mut FrankenTorchSession,
    vector: TensorNodeId,
    parameters: &[TensorNodeId],
) -> Result<(), AutogradError> {
    let (flat_values, flat_meta) = session.tensor_values_meta(vector)?;
    if flat_meta.shape().len() != 1 {
        return Err(gradient_utils_error(
            "vector_to_parameters requires a 1D source vector",
        ));
    }

    let mut offset = 0usize;
    session.no_grad_enter();
    for &parameter in parameters {
        let (param_values, param_meta) = session.tensor_values_meta(parameter)?;
        let len = param_values.len();
        let Some(end) = offset.checked_add(len) else {
            session.no_grad_exit();
            return Err(gradient_utils_error("vector_to_parameters offset overflow"));
        };
        if end > flat_values.len() {
            session.no_grad_exit();
            return Err(gradient_utils_error(
                "vector_to_parameters source vector is shorter than parameter footprint",
            ));
        }

        let chunk_node = session.tensor_variable(
            flat_values[offset..end].to_vec(),
            param_meta.shape().to_vec(),
            false,
        )?;
        session.tensor_zero_(parameter)?;
        session.tensor_add_(parameter, chunk_node)?;
        offset = end;
    }
    session.no_grad_exit();

    if offset != flat_values.len() {
        return Err(gradient_utils_error(
            "vector_to_parameters source vector has unused trailing values",
        ));
    }

    Ok(())
}

/// Fully connected linear layer: output = input @ weight^T + bias.
pub struct Linear {
    weight: TensorNodeId,
    bias: Option<TensorNodeId>,
    in_features: usize,
    out_features: usize,
}

impl Linear {
    /// Create a new Linear layer with Kaiming uniform initialization.
    ///
    /// `weight` has shape `[out_features, in_features]`.
    /// `bias` (if enabled) has shape `[out_features]` (1-D), matching
    /// PyTorch's `Linear.bias` so `state_dict` round-trips against a
    /// torch checkpoint. Forward broadcasts it over the batch dims.
    pub fn new(
        session: &mut FrankenTorchSession,
        in_features: usize,
        out_features: usize,
        use_bias: bool,
    ) -> Result<Self, AutogradError> {
        if in_features == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "linear layer requires in_features > 0",
                },
            )));
        }
        // PyTorch Linear initialization: U(-bound, bound) where bound = sqrt(1 / in_features)
        let bound = 1.0 / (in_features as f64).sqrt();

        // Initialize weight
        let weight_rand = session.rand(vec![out_features, in_features], false)?;
        let scale_tensor = session.full(vec![out_features, in_features], 2.0 * bound, false)?;
        let weight_scaled = session.tensor_mul(weight_rand, scale_tensor)?;
        let shift_tensor = session.full(vec![out_features, in_features], bound, false)?;
        let weight_shifted = session.tensor_sub(weight_scaled, shift_tensor)?;

        let weight_values = session.tensor_values(weight_shifted)?;
        let weight =
            session.tensor_variable(weight_values, vec![out_features, in_features], true)?;

        // Initialize bias
        let bias = if use_bias {
            let bias_rand = session.rand(vec![out_features], false)?;
            let bias_scale = session.full(vec![out_features], 2.0 * bound, false)?;
            let bias_scaled = session.tensor_mul(bias_rand, bias_scale)?;
            let bias_shift = session.full(vec![out_features], bound, false)?;
            let bias_shifted = session.tensor_sub(bias_scaled, bias_shift)?;

            let bias_values = session.tensor_values(bias_shifted)?;
            Some(session.tensor_variable(bias_values, vec![out_features], true)?)
        } else {
            None
        };

        Ok(Self {
            weight,
            bias,
            in_features,
            out_features,
        })
    }

    /// Access the weight parameter node ID.
    #[must_use]
    pub fn weight(&self) -> TensorNodeId {
        self.weight
    }

    /// Access the bias parameter node ID (if present).
    #[must_use]
    pub fn bias(&self) -> Option<TensorNodeId> {
        self.bias
    }

    /// Input feature dimension.
    #[must_use]
    pub fn in_features(&self) -> usize {
        self.in_features
    }

    /// Output feature dimension.
    #[must_use]
    pub fn out_features(&self) -> usize {
        self.out_features
    }

    fn no_grad_f64_fast_path(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<Option<TensorNodeId>, AutogradError> {
        if session.is_grad_enabled()
            || !matches!(session.tensor_dtype(input)?, DType::F64)
            || !matches!(session.tensor_dtype(self.weight)?, DType::F64)
        {
            return Ok(None);
        }

        let input_shape = session.tensor_shape(input)?;
        let Some((&in_features, leading_shape)) = input_shape.split_last() else {
            return Ok(None);
        };
        if !in_features.eq(&self.in_features) {
            return Ok(None);
        }

        let weight_shape = session.tensor_shape(self.weight)?;
        let [weight_out, weight_in] = weight_shape.as_slice() else {
            return Ok(None);
        };
        if !weight_out.eq(&self.out_features) || !weight_in.eq(&self.in_features) {
            return Ok(None);
        }

        let Some(batch) = leading_shape
            .iter()
            .try_fold(1usize, |acc, dim| acc.checked_mul(*dim))
        else {
            return Ok(None);
        };
        if batch == 0 || self.in_features == 0 || self.out_features == 0 {
            return Ok(None);
        }

        let bias_values = match self.bias {
            Some(bias) => {
                if !matches!(session.tensor_dtype(bias)?, DType::F64) {
                    return Ok(None);
                }
                let bias_shape = session.tensor_shape(bias)?;
                let [bias_out] = bias_shape.as_slice() else {
                    return Ok(None);
                };
                if !bias_out.eq(&self.out_features) {
                    return Ok(None);
                }
                Some(session.tensor_values(bias)?)
            }
            None => None,
        };

        let mut out_shape = input_shape;
        if let Some(last) = out_shape.last_mut() {
            *last = self.out_features;
        }
        let input_values = session.tensor_values(input)?;
        let weight_values = session.tensor_values(self.weight)?;
        let output_values = ft_kernel_cpu::linear_tensor_f64(
            &input_values,
            &weight_values,
            bias_values.as_deref(),
            batch,
            self.in_features,
            self.out_features,
        );
        Ok(Some(session.tensor_variable(
            output_values,
            out_shape,
            false,
        )?))
    }
}

impl Module for Linear {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if let Some(output) = self.no_grad_f64_fast_path(session, input)? {
            return Ok(output);
        }

        // Transpose weight: [out, in] -> [in, out]
        let weight_t = session.tensor_transpose(self.weight, 0, 1)?;
        // output = input @ weight^T => [batch, in] @ [in, out] => [batch, out]
        let output = session.tensor_matmul(input, weight_t)?;

        match self.bias {
            Some(bias) => {
                let out_shape = {
                    let (_, meta) = session.tensor_values_meta(output)?;
                    meta.shape().to_vec()
                };
                // bias is 1-D [out_features]; reshape to a rank-matched
                // broadcast shape (1s in the leading dims) before
                // expanding. `tensor_expand` only stretches size-1 dims;
                // it cannot prepend new ones.
                let mut bias_shape = vec![1usize; out_shape.len()];
                if let Some(last) = bias_shape.last_mut() {
                    *last = self.out_features;
                }
                let bias_reshaped = session.tensor_reshape(bias, bias_shape)?;
                let expanded_bias = session.tensor_expand(bias_reshaped, out_shape)?;
                session.tensor_add(output, expanded_bias)
            }
            None => Ok(output),
        }
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        let mut params = vec![self.weight];
        if let Some(bias) = self.bias {
            params.push(bias);
        }
        params
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        let mut params = vec![("weight", self.weight)];
        if let Some(bias) = self.bias {
            params.push(("bias", bias));
        }
        params
    }
}

/// Lazy linear layer that defers weight initialization until first forward.
///
/// Equivalent to `torch.nn.LazyLinear(out_features)`. Infers `in_features`
/// from the input tensor shape on the first `forward` call.
pub struct LazyLinear {
    out_features: usize,
    use_bias: bool,
    materialized: Option<Linear>,
}

impl LazyLinear {
    #[must_use]
    pub fn new(out_features: usize, use_bias: bool) -> Self {
        Self {
            out_features,
            use_bias,
            materialized: None,
        }
    }

    pub fn is_materialized(&self) -> bool {
        self.materialized.is_some()
    }

    pub fn materialize(
        &mut self,
        session: &mut FrankenTorchSession,
        in_features: usize,
    ) -> Result<(), AutogradError> {
        if self.materialized.is_none() {
            self.materialized = Some(Linear::new(
                session,
                in_features,
                self.out_features,
                self.use_bias,
            )?);
        }
        Ok(())
    }

    pub fn forward_lazy(
        &mut self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = session.tensor_shape(input)?;
        if shape.is_empty() {
            return Err(incompatible_error("LazyLinear: empty input shape"));
        }
        let in_features = *shape.last().unwrap();
        self.materialize(session, in_features)?;
        self.materialized.as_ref().unwrap().forward(session, input)
    }

    pub fn parameters(&self) -> Vec<TensorNodeId> {
        self.materialized
            .as_ref()
            .map(|m| m.parameters())
            .unwrap_or_default()
    }
}

/// Bilinear transformation module: `y_k = x1^T W_k x2 + b_k`.
///
/// Equivalent to `torch.nn.Bilinear(in1_features, in2_features, out_features)`.
/// Weight has shape `[out_features, in1_features, in2_features]`.
/// Bias has shape `[out_features]`.
///
/// Note: the `forward` method takes only `input` (`x1`). The second input `x2`
/// must be provided via `forward_bilinear`.
pub struct Bilinear {
    weight: TensorNodeId,
    bias: Option<TensorNodeId>,
    in1_features: usize,
    in2_features: usize,
    out_features: usize,
}

impl Bilinear {
    /// Create a new Bilinear layer with uniform initialization.
    pub fn new(
        session: &mut FrankenTorchSession,
        in1_features: usize,
        in2_features: usize,
        out_features: usize,
        use_bias: bool,
    ) -> Result<Self, AutogradError> {
        if in1_features == 0 || in2_features == 0 || out_features == 0 {
            return Err(incompatible_error(
                "Bilinear requires positive in1_features, in2_features, and out_features",
            ));
        }

        let bound = 1.0 / (in1_features as f64).sqrt();
        let feature_product =
            checked_mul(in1_features, in2_features, "Bilinear feature size overflow")?;
        let total = checked_mul(
            out_features,
            feature_product,
            "Bilinear weight size overflow",
        )?;

        let weight_rand = session.rand(vec![total], false)?;
        let scale = session.full(vec![total], 2.0 * bound, false)?;
        let w_scaled = session.tensor_mul(weight_rand, scale)?;
        let shift = session.full(vec![total], bound, false)?;
        let w_shifted = session.tensor_sub(w_scaled, shift)?;

        let w_vals = session.tensor_values(w_shifted)?;
        let weight = session.tensor_variable(
            w_vals,
            vec![out_features, in1_features, in2_features],
            true,
        )?;

        let bias = if use_bias {
            let b_rand = session.rand(vec![out_features], false)?;
            let b_scale = session.full(vec![out_features], 2.0 * bound, false)?;
            let b_scaled = session.tensor_mul(b_rand, b_scale)?;
            let b_shift = session.full(vec![out_features], bound, false)?;
            let b_shifted = session.tensor_sub(b_scaled, b_shift)?;
            let b_vals = session.tensor_values(b_shifted)?;
            Some(session.tensor_variable(b_vals, vec![out_features], true)?)
        } else {
            None
        };

        Ok(Self {
            weight,
            bias,
            in1_features,
            in2_features,
            out_features,
        })
    }

    /// Compute bilinear forward: `y_k = x1^T W_k x2 + b_k`.
    ///
    /// `x1` has shape `[*, in1_features]`, `x2` has shape `[*, in2_features]`.
    /// Output has shape `[*, out_features]`.
    pub fn forward_bilinear(
        &self,
        session: &mut FrankenTorchSession,
        x1: TensorNodeId,
        x2: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let x1_shape = session.tensor_shape(x1)?;
        let x2_shape = session.tensor_shape(x2)?;
        if x1_shape.is_empty() || x2_shape.is_empty() {
            return Err(incompatible_error("bilinear: inputs must be at least 1-D"));
        }
        let x1_batch_shape = &x1_shape[..x1_shape.len() - 1];
        let x2_batch_shape = &x2_shape[..x2_shape.len() - 1];
        if !x1_batch_shape.iter().eq(x2_batch_shape.iter()) {
            return Err(incompatible_error(
                "bilinear: input batch dimensions must match",
            ));
        }
        let in1 = self.in1_features;
        let in2 = self.in2_features;
        let out = self.out_features;

        // Handle batched inputs
        let batch = if x1_batch_shape.is_empty() {
            1
        } else {
            checked_shape_numel(x1_batch_shape, "bilinear: batch shape overflow")?
        };
        let x1_last = *x1_shape.last().unwrap_or(&0);
        let x2_last = *x2_shape.last().unwrap_or(&0);
        if x1_last != in1 || x2_last != in2 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "bilinear: input feature dimensions mismatch",
                },
            )));
        }

        // Compose through autograd-aware primitives. Tracked under
        // frankentorch-yn0i. Math:
        //   y[b, k] = sum_{i, j} x1[b, i] * W[k, i, j] * x2[b, j]
        //          = (vec(x1[b] outer x2[b])) · vec(W[k])
        // i.e. flatten the per-batch outer product into [batch, in1*in2]
        // and matmul with reshape(W, [out, in1*in2]).T.
        let x1_flat = session.tensor_reshape(x1, vec![batch, in1])?;
        let x2_flat = session.tensor_reshape(x2, vec![batch, in2])?;
        let x1_b = session.tensor_unsqueeze(x1_flat, 2)?; // [batch, in1, 1]
        let x2_b = session.tensor_unsqueeze(x2_flat, 1)?; // [batch, 1, in2]
        let x1_b_e = session.tensor_expand(x1_b, vec![batch, in1, in2])?;
        let x2_b_e = session.tensor_expand(x2_b, vec![batch, in1, in2])?;
        let outer = session.tensor_mul(x1_b_e, x2_b_e)?; // [batch, in1, in2]
        let outer_flat = session.tensor_reshape(outer, vec![batch, in1 * in2])?;

        let w_flat = session.tensor_reshape(self.weight, vec![out, in1 * in2])?;
        let w_flat_t = session.tensor_transpose(w_flat, 0, 1)?; // [in1*in2, out]
        let result = session.tensor_matmul(outer_flat, w_flat_t)?; // [batch, out]

        let out_shape = if x1_shape.len() == 1 {
            vec![out]
        } else {
            let mut s = x1_shape[..x1_shape.len() - 1].to_vec();
            s.push(out);
            s
        };
        let result_node = session.tensor_reshape(result, out_shape.clone())?;

        if let Some(bias) = self.bias {
            // bias is shape [out_features] (rank 1); reshape to a
            // rank-matched broadcast shape (1s in leading dims,
            // out_features in last) before expanding to out_shape.
            // tensor_expand only broadcasts size-1 dims; it cannot
            // add new dims. Tracked under frankentorch-3t8u.
            let mut bias_broadcast_shape = vec![1usize; out_shape.len()];
            *bias_broadcast_shape.last_mut().unwrap() = self.out_features;
            let bias_reshaped = session.tensor_reshape(bias, bias_broadcast_shape)?;
            let expanded_bias = session.tensor_expand(bias_reshaped, out_shape)?;
            session.tensor_add(result_node, expanded_bias)
        } else {
            Ok(result_node)
        }
    }

    /// Access the weight parameter.
    #[must_use]
    pub fn weight(&self) -> TensorNodeId {
        self.weight
    }

    /// Access the bias parameter.
    #[must_use]
    pub fn bias(&self) -> Option<TensorNodeId> {
        self.bias
    }
}

impl Module for Bilinear {
    fn forward(
        &self,
        _session: &mut FrankenTorchSession,
        _input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        Err(AutogradError::Dispatch(DispatchError::Key(
            DispatchKeyError::IncompatibleSet {
                reason: "bilinear: use forward_bilinear(session, x1, x2) instead of forward()",
            },
        )))
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        let mut params = vec![self.weight];
        if let Some(bias) = self.bias {
            params.push(bias);
        }
        params
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        let mut params = vec![("weight", self.weight)];
        if let Some(bias) = self.bias {
            params.push(("bias", bias));
        }
        params
    }
}

/// Extracts sliding local blocks from a batched input tensor (im2col).
///
/// Equivalent to `torch.nn.Unfold(kernel_size, dilation=1, padding=0, stride=1)`.
/// Input shape: `[N, C, H, W]` (4-D batched image tensor).
/// Output shape: `[N, C * kH * kW, L]` where `L` is the number of valid positions.
pub struct Unfold {
    kernel_h: usize,
    kernel_w: usize,
    dilation_h: usize,
    dilation_w: usize,
    padding_h: usize,
    padding_w: usize,
    stride_h: usize,
    stride_w: usize,
}

impl Unfold {
    /// Create a new Unfold module.
    ///
    /// `kernel_size`: (height, width) of the sliding window.
    /// `dilation`, `padding`, `stride`: optional, default to (1,1), (0,0), (1,1).
    #[must_use]
    pub fn new(kernel_size: (usize, usize)) -> Self {
        Self {
            kernel_h: kernel_size.0,
            kernel_w: kernel_size.1,
            dilation_h: 1,
            dilation_w: 1,
            padding_h: 0,
            padding_w: 0,
            stride_h: 1,
            stride_w: 1,
        }
    }

    /// Set dilation.
    #[must_use]
    pub fn dilation(mut self, dilation: (usize, usize)) -> Self {
        self.dilation_h = dilation.0;
        self.dilation_w = dilation.1;
        self
    }

    /// Set padding.
    #[must_use]
    pub fn padding(mut self, padding: (usize, usize)) -> Self {
        self.padding_h = padding.0;
        self.padding_w = padding.1;
        self
    }

    /// Set stride.
    #[must_use]
    pub fn stride(mut self, stride: (usize, usize)) -> Self {
        self.stride_h = stride.0;
        self.stride_w = stride.1;
        self
    }

    fn output_positions(&self, h: usize, w: usize) -> Result<(usize, usize), AutogradError> {
        let out_h = Self::output_position_dim(
            h,
            self.kernel_h,
            self.dilation_h,
            self.padding_h,
            self.stride_h,
        )?;
        let out_w = Self::output_position_dim(
            w,
            self.kernel_w,
            self.dilation_w,
            self.padding_w,
            self.stride_w,
        )?;
        Ok((out_h, out_w))
    }

    fn output_position_dim(
        input: usize,
        kernel: usize,
        dilation: usize,
        padding: usize,
        stride: usize,
    ) -> Result<usize, AutogradError> {
        if kernel == 0 || dilation == 0 || stride == 0 {
            return Err(incompatible_error(
                "unfold: kernel_size, dilation, and stride dimensions must be greater than zero",
            ));
        }

        let effective_span = checked_mul(dilation, kernel - 1, "unfold effective kernel overflow")?;
        let effective_kernel = checked_add(effective_span, 1, "unfold effective kernel overflow")?;
        let pad = checked_mul(2, padding, "unfold padded input overflow")?;
        let padded = checked_add(input, pad, "unfold padded input overflow")?;
        let positions = padded.saturating_sub(effective_kernel) / stride;
        checked_add(positions, 1, "unfold output positions overflow")
    }
}

impl Module for Unfold {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.kernel_h == 0
            || self.kernel_w == 0
            || self.dilation_h == 0
            || self.dilation_w == 0
            || self.stride_h == 0
            || self.stride_w == 0
        {
            return Err(incompatible_error(
                "unfold: kernel_size, dilation, and stride dimensions must be greater than zero",
            ));
        }

        // Compose Unfold through autograd primitives so the backward
        // pass actually flows through the input. The previous
        // implementation read tensor_values, computed the gather in
        // plain f64 math, and rebuilt a fresh leaf with
        // requires_grad=false — silently severing the tape.
        //
        // Strategy:
        //   1. Pad input with zeros along H and W (so out-of-bounds
        //      reads in the kernel sweep become legitimate zero
        //      reads from the padded buffer).
        //   2. Flatten the padded input to 1-D.
        //   3. Build a static index tensor mapping each (batch, row,
        //      col_idx) output position to the corresponding flat
        //      padded-input index.
        //   4. tensor_gather along dim 0 with that index → flat output.
        //   5. Reshape to [N, block_size, L].
        //
        // tensor_pad / tensor_reshape / tensor_gather all have
        // backward kernels in ft-autograd, so the resulting graph is
        // fully differentiable — gather's backward is exactly the
        // scatter_add that Fold computes, which is the analytical
        // transpose of Unfold.
        let shape = session.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "unfold: input must be 4-D [N, C, H, W]",
                },
            )));
        }
        let (n, c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let (out_h, out_w) = self.output_positions(h, w)?;
        let l = checked_mul(out_h, out_w, "unfold output positions overflow")?;
        let kernel_area = checked_mul(self.kernel_h, self.kernel_w, "unfold kernel area overflow")?;
        let block_size = checked_mul(c, kernel_area, "unfold block size overflow")?;

        let pad_h = checked_mul(2, self.padding_h, "unfold padded height overflow")?;
        let pad_w = checked_mul(2, self.padding_w, "unfold padded width overflow")?;
        let padded_h = checked_add(h, pad_h, "unfold padded height overflow")?;
        let padded_w = checked_add(w, pad_w, "unfold padded width overflow")?;

        // Step 1: Pad along H and W. tensor_pad uses [left, right]
        // per dim, innermost-first → [pad_w, pad_w, pad_h, pad_h]
        // for a [N, C, H, W] tensor.
        let padded_input = if self.padding_h > 0 || self.padding_w > 0 {
            session.tensor_pad(
                input,
                &[
                    self.padding_w,
                    self.padding_w,
                    self.padding_h,
                    self.padding_h,
                ],
                0.0,
            )?
        } else {
            input
        };

        // Step 2: Flatten to 1-D.
        let flat_total = checked_shape_numel(
            &[n, c, padded_h, padded_w],
            "unfold flat input shape overflow",
        )?;
        let flat_padded = session.tensor_reshape(padded_input, vec![flat_total])?;

        // Step 3: Build the gather index. The output [N, block_size, L]
        // is laid out contiguously, so iterate batch → row → col_idx in
        // lexicographic order to match. row decomposes as
        // (ci, kh_idx, kw_idx) and col_idx as (oh, ow).
        let out_numel = checked_shape_numel(&[n, block_size, l], "unfold output shape overflow")?;
        let mut index_vals = Vec::with_capacity(out_numel);
        for batch in 0..n {
            for ci in 0..c {
                for kh in 0..self.kernel_h {
                    for kw in 0..self.kernel_w {
                        for oh in 0..out_h {
                            for ow in 0..out_w {
                                let ih_pad = oh * self.stride_h + kh * self.dilation_h;
                                let iw_pad = ow * self.stride_w + kw * self.dilation_w;
                                let flat = batch * c * padded_h * padded_w
                                    + ci * padded_h * padded_w
                                    + ih_pad * padded_w
                                    + iw_pad;
                                #[allow(clippy::cast_precision_loss)]
                                index_vals.push(flat as f64);
                            }
                        }
                    }
                }
            }
        }

        let index = session.tensor_variable(index_vals, vec![out_numel], false)?;

        // Step 4: Gather flat-padded values at the computed positions.
        let gathered = session.tensor_gather(flat_padded, 0, index)?;

        // Step 5: Reshape to [N, block_size, L].
        session.tensor_reshape(gathered, vec![n, block_size, l])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Combines an array of sliding local blocks into a large containing tensor (col2im).
///
/// Equivalent to `torch.nn.Fold(output_size, kernel_size, dilation=1, padding=0, stride=1)`.
/// Input shape: `[N, C * kH * kW, L]`.
/// Output shape: `[N, C, output_h, output_w]`.
///
/// Overlapping blocks are summed (this is the transpose of `Unfold`).
pub struct Fold {
    output_h: usize,
    output_w: usize,
    kernel_h: usize,
    kernel_w: usize,
    dilation_h: usize,
    dilation_w: usize,
    padding_h: usize,
    padding_w: usize,
    stride_h: usize,
    stride_w: usize,
}

impl Fold {
    /// Create a new Fold module.
    ///
    /// `output_size`: target (H, W). `kernel_size`: (kH, kW).
    #[must_use]
    pub fn new(output_size: (usize, usize), kernel_size: (usize, usize)) -> Self {
        Self {
            output_h: output_size.0,
            output_w: output_size.1,
            kernel_h: kernel_size.0,
            kernel_w: kernel_size.1,
            dilation_h: 1,
            dilation_w: 1,
            padding_h: 0,
            padding_w: 0,
            stride_h: 1,
            stride_w: 1,
        }
    }

    /// Set dilation.
    #[must_use]
    pub fn dilation(mut self, dilation: (usize, usize)) -> Self {
        self.dilation_h = dilation.0;
        self.dilation_w = dilation.1;
        self
    }

    /// Set padding.
    #[must_use]
    pub fn padding(mut self, padding: (usize, usize)) -> Self {
        self.padding_h = padding.0;
        self.padding_w = padding.1;
        self
    }

    /// Set stride.
    #[must_use]
    pub fn stride(mut self, stride: (usize, usize)) -> Self {
        self.stride_h = stride.0;
        self.stride_w = stride.1;
        self
    }

    fn output_positions(&self) -> Result<(usize, usize), AutogradError> {
        let out_h = Self::output_position_dim(
            self.output_h,
            self.kernel_h,
            self.dilation_h,
            self.padding_h,
            self.stride_h,
        )?;
        let out_w = Self::output_position_dim(
            self.output_w,
            self.kernel_w,
            self.dilation_w,
            self.padding_w,
            self.stride_w,
        )?;
        Ok((out_h, out_w))
    }

    fn output_position_dim(
        output: usize,
        kernel: usize,
        dilation: usize,
        padding: usize,
        stride: usize,
    ) -> Result<usize, AutogradError> {
        if kernel == 0 || dilation == 0 || stride == 0 {
            return Err(incompatible_error(
                "fold: kernel_size, dilation, and stride dimensions must be greater than zero",
            ));
        }

        let effective_span = checked_mul(dilation, kernel - 1, "fold effective kernel overflow")?;
        let effective_kernel = checked_add(effective_span, 1, "fold effective kernel overflow")?;
        let pad = checked_mul(2, padding, "fold padded output overflow")?;
        let padded = checked_add(output, pad, "fold padded output overflow")?;
        let positions = padded.saturating_sub(effective_kernel) / stride;
        checked_add(positions, 1, "fold output positions overflow")
    }
}

impl Module for Fold {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.kernel_h == 0
            || self.kernel_w == 0
            || self.dilation_h == 0
            || self.dilation_w == 0
            || self.stride_h == 0
            || self.stride_w == 0
        {
            return Err(incompatible_error(
                "fold: kernel_size, dilation, and stride dimensions must be greater than zero",
            ));
        }

        let shape = session.tensor_shape(input)?;
        if shape.len() != 3 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "fold: input must be 3-D [N, C*kH*kW, L]",
                },
            )));
        }
        let (n, block_size, l) = (shape[0], shape[1], shape[2]);
        let (out_h, out_w) = self.output_positions()?;
        let expected_l = checked_mul(out_h, out_w, "fold expected L overflow")?;
        if l != expected_l {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "fold: L does not match output_size/kernel/stride/padding",
                },
            )));
        }

        let kernel_area = checked_mul(self.kernel_h, self.kernel_w, "fold kernel area overflow")?;
        if block_size % kernel_area != 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "fold: block_size must be divisible by kH*kW",
                },
            )));
        }
        let c = block_size / kernel_area;

        let h = self.output_h;
        let w = self.output_w;
        let padded_h = checked_add(h, self.padding_h, "fold padded height overflow")?;
        let padded_w = checked_add(w, self.padding_w, "fold padded width overflow")?;
        let output_numel = checked_shape_numel(&[n, c, h, w], "fold output shape overflow")?;
        let input_numel = checked_shape_numel(&[n, block_size, l], "fold input shape overflow")?;

        let input_dtype = session.tensor_dtype(input)?;
        let zero_output = match input_dtype {
            DType::F64 => {
                session.tensor_variable(vec![0.0; output_numel], vec![output_numel], false)?
            }
            DType::F32 => session.tensor_variable_f32(
                vec![0.0_f32; output_numel],
                vec![output_numel],
                false,
            )?,
            _ => {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "fold: input must be f32 or f64",
                    },
                )));
            }
        };

        let mut index_vals = Vec::with_capacity(input_numel);
        let mut mask_vals = Vec::with_capacity(input_numel);
        for batch in 0..n {
            for ci in 0..c {
                for kh in 0..self.kernel_h {
                    for kw in 0..self.kernel_w {
                        for oh in 0..out_h {
                            for ow in 0..out_w {
                                #[allow(clippy::cast_precision_loss)]
                                let mut flat_dst = 0.0_f64;
                                let mut valid = false;
                                let ih = oh * self.stride_h + kh * self.dilation_h;
                                let iw = ow * self.stride_w + kw * self.dilation_w;
                                if ih >= self.padding_h
                                    && ih < padded_h
                                    && iw >= self.padding_w
                                    && iw < padded_w
                                {
                                    let dst_h = ih - self.padding_h;
                                    let dst_w = iw - self.padding_w;
                                    let flat = batch * c * h * w + ci * h * w + dst_h * w + dst_w;
                                    flat_dst = flat as f64;
                                    valid = true;
                                }
                                index_vals.push(flat_dst);
                                mask_vals.push(valid);
                            }
                        }
                    }
                }
            }
        }

        let flat_input = session.tensor_reshape(input, vec![input_numel])?;
        let mask = match input_dtype {
            DType::F64 => session.tensor_variable(
                mask_vals
                    .iter()
                    .map(|&valid| if valid { 1.0 } else { 0.0 })
                    .collect(),
                vec![input_numel],
                false,
            )?,
            DType::F32 => session.tensor_variable_f32(
                mask_vals
                    .into_iter()
                    .map(|valid| if valid { 1.0_f32 } else { 0.0_f32 })
                    .collect(),
                vec![input_numel],
                false,
            )?,
            _ => unreachable!("fold input dtype was already validated"),
        };
        let masked_input = session.tensor_mul(flat_input, mask)?;
        let index = session.tensor_variable(index_vals, vec![input_numel], false)?;
        let flat_output = session.tensor_scatter_add(zero_output, 0, index, masked_input)?;

        session.tensor_reshape(flat_output, vec![n, c, h, w])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

