/// 1D average pooling module.
///
/// Input: `[N, C, L]`. Output: `[N, C, L_out]` where `L_out = (L - kernel_size) / stride + 1`.
pub struct AvgPool1d {
    kernel_size: usize,
    stride: usize,
}

impl AvgPool1d {
    /// Create an AvgPool1d module. If stride is 0, it defaults to kernel_size.
    #[must_use]
    pub fn new(kernel_size: usize, stride: usize) -> Self {
        let effective_stride = if stride == 0 { kernel_size } else { stride };
        Self {
            kernel_size,
            stride: effective_stride,
        }
    }
}

impl Module for AvgPool1d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        validate_positive_pooling_dims(
            &[self.kernel_size, self.stride],
            "AvgPool1d kernel_size and stride must be greater than zero",
        )?;

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 3 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool1d expects 3D input [N, C, L]",
                },
            )));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        let l_in = input_shape[2];

        if l_in < self.kernel_size {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool1d input length smaller than kernel_size",
                },
            )));
        }

        let l_out = (l_in - self.kernel_size) / self.stride + 1;

        // For each output position, narrow the input, mean over the kernel dimension
        let mut slices = Vec::with_capacity(l_out);
        for l in 0..l_out {
            let start = l * self.stride;
            // narrow(input, dim=2, start, kernel_size) -> [N, C, K]
            let patch = session.tensor_narrow(input, 2, start, self.kernel_size)?;
            // mean_dim over dim 2 -> [N, C]
            let avg = session.tensor_mean_dim(patch, 2)?;
            // unsqueeze -> [N, C, 1]
            let avg_us = session.tensor_unsqueeze(avg, 2)?;
            slices.push(avg_us);
        }

        // cat along dim 2: [N, C, L_out]
        let output = session.tensor_cat(&slices, 2)?;

        // Verify shape
        debug_assert_eq!(
            {
                let (_, m) = session.tensor_values_meta(output).unwrap();
                m.shape().to_vec()
            },
            vec![batch_size, channels, l_out]
        );

        Ok(output)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Multi-head attention module.
///
/// Implements scaled dot-product attention with multiple heads.
/// Input: `[N, S, E]` where E = embed_dim. Output: `[N, S, E]`.
///
/// When used via the `Module` trait, performs self-attention (query = key = value = input).
/// Use `forward_qkv` for cross-attention with separate query, key, value.
pub struct MultiheadAttention {
    q_proj: Linear,
    k_proj: Linear,
    v_proj: Linear,
    out_proj: Linear,
    num_heads: usize,
    head_dim: usize,
    scale: f64,
}

impl MultiheadAttention {
    /// Create a new MultiheadAttention module.
    ///
    /// `embed_dim` must be divisible by `num_heads`.
    pub fn new(
        session: &mut FrankenTorchSession,
        embed_dim: usize,
        num_heads: usize,
    ) -> Result<Self, AutogradError> {
        if embed_dim == 0 || num_heads == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MultiheadAttention requires positive embed_dim and num_heads",
                },
            )));
        }
        if !embed_dim.is_multiple_of(num_heads) {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "embed_dim must be divisible by num_heads",
                },
            )));
        }

        let head_dim = embed_dim / num_heads;
        let q_proj = Linear::new(session, embed_dim, embed_dim, true)?;
        let k_proj = Linear::new(session, embed_dim, embed_dim, true)?;
        let v_proj = Linear::new(session, embed_dim, embed_dim, true)?;
        let out_proj = Linear::new(session, embed_dim, embed_dim, true)?;

        Ok(Self {
            q_proj,
            k_proj,
            v_proj,
            out_proj,
            num_heads,
            head_dim,
            scale: 1.0 / (head_dim as f64).sqrt(),
        })
    }

    /// Number of attention heads.
    #[must_use]
    pub fn num_heads(&self) -> usize {
        self.num_heads
    }

    fn no_grad_f64_projection_values(
        session: &mut FrankenTorchSession,
        projection: &Linear,
        input_values: &[f64],
        batch_tokens: usize,
        embed_dim: usize,
    ) -> Result<Option<Vec<f64>>, AutogradError> {
        if projection.in_features() != embed_dim || projection.out_features() != embed_dim {
            return Ok(None);
        }

        let (weight_values, weight_meta) = session.tensor_values_meta(projection.weight)?;
        if weight_meta.dtype() != DType::F64
            || weight_meta.device() != Device::Cpu
            || weight_meta.shape() != [embed_dim, embed_dim]
        {
            return Ok(None);
        }

        let bias_values = match projection.bias {
            Some(bias) => {
                let (values, meta) = session.tensor_values_meta(bias)?;
                if meta.dtype() != DType::F64
                    || meta.device() != Device::Cpu
                    || meta.shape() != [embed_dim]
                {
                    return Ok(None);
                }
                Some(values)
            }
            None => None,
        };

        Ok(Some(ft_kernel_cpu::linear_tensor_f64(
            input_values,
            &weight_values,
            bias_values.as_deref(),
            batch_tokens,
            embed_dim,
            embed_dim,
        )))
    }

    fn pack_attention_heads(
        values: &[f64],
        seq_len: usize,
        num_heads: usize,
        head_dim: usize,
        embed_dim: usize,
    ) -> Vec<f64> {
        let mut packed = vec![0.0; values.len()];
        let batch_stride = seq_len * embed_dim;
        let head_stride = seq_len * head_dim;
        for (batch, batch_values) in values.chunks_exact(batch_stride).enumerate() {
            for (seq, token_values) in batch_values.chunks_exact(embed_dim).enumerate() {
                for (head, head_values) in token_values.chunks_exact(head_dim).enumerate() {
                    let dst = (batch * num_heads + head) * head_stride + seq * head_dim;
                    packed[dst..dst + head_dim].copy_from_slice(head_values);
                }
            }
        }
        packed
    }

    fn concat_attention_heads(
        values: &[f64],
        batch_size: usize,
        seq_len: usize,
        num_heads: usize,
        head_dim: usize,
        embed_dim: usize,
    ) -> Vec<f64> {
        let mut concat = vec![0.0; batch_size * seq_len * embed_dim];
        let head_stride = seq_len * head_dim;
        let batch_stride = seq_len * embed_dim;
        for batch in 0..batch_size {
            for head in 0..num_heads {
                let src_head = &values[(batch * num_heads + head) * head_stride
                    ..(batch * num_heads + head + 1) * head_stride];
                for (seq, head_values) in src_head.chunks_exact(head_dim).enumerate() {
                    let dst = batch * batch_stride + seq * embed_dim + head * head_dim;
                    concat[dst..dst + head_dim].copy_from_slice(head_values);
                }
            }
        }
        concat
    }

    fn no_grad_f64_self_attention_fast_path(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<Option<TensorNodeId>, AutogradError> {
        if session.is_grad_enabled() {
            return Ok(None);
        }

        let (input_values, input_meta) = session.tensor_values_meta(input)?;
        if input_meta.dtype() != DType::F64 || input_meta.device() != Device::Cpu {
            return Ok(None);
        }
        let [batch_size, seq_len, embed_dim] = input_meta.shape() else {
            return Ok(None);
        };
        let (batch_size, seq_len, embed_dim) = (*batch_size, *seq_len, *embed_dim);
        if batch_size == 0 || seq_len == 0 || embed_dim == 0 {
            return Ok(None);
        }
        let Some(expected_embed) = self.num_heads.checked_mul(self.head_dim) else {
            return Ok(None);
        };
        if embed_dim != expected_embed {
            return Ok(None);
        }
        let Some(batch_tokens) = batch_size.checked_mul(seq_len) else {
            return Ok(None);
        };
        let Some(batch_heads) = batch_size.checked_mul(self.num_heads) else {
            return Ok(None);
        };
        if batch_heads.checked_mul(seq_len).is_none()
            || seq_len.checked_mul(seq_len).is_none()
            || batch_heads
                .checked_mul(seq_len)
                .and_then(|n| n.checked_mul(seq_len))
                .is_none()
        {
            return Ok(None);
        }

        let Some(mut q_heads) = Self::no_grad_f64_projection_values(
            session,
            &self.q_proj,
            &input_values,
            batch_tokens,
            embed_dim,
        )?
        else {
            return Ok(None);
        };
        let Some(k_values) = Self::no_grad_f64_projection_values(
            session,
            &self.k_proj,
            &input_values,
            batch_tokens,
            embed_dim,
        )?
        else {
            return Ok(None);
        };
        let Some(v_values) = Self::no_grad_f64_projection_values(
            session,
            &self.v_proj,
            &input_values,
            batch_tokens,
            embed_dim,
        )?
        else {
            return Ok(None);
        };

        let q_heads =
            Self::pack_attention_heads(&q_heads, seq_len, self.num_heads, self.head_dim, embed_dim);
        let k_heads = Self::pack_attention_heads(
            &k_values,
            seq_len,
            self.num_heads,
            self.head_dim,
            embed_dim,
        );
        let v_heads = Self::pack_attention_heads(
            &v_values,
            seq_len,
            self.num_heads,
            self.head_dim,
            embed_dim,
        );

        // Flash attention: fused QK^T + stable row-softmax + scores@V in cache
        // tiles, never materialising the [batch_heads, S, S] score matrix (the
        // bmm path built AND softmaxed the full ~67 MB scores at S=1024). The
        // kernel scales the scores by `self.scale` internally (equivalent to
        // scaling Q) and applies no causal mask — matching this self-attention
        // path's plain softmax over all keys. Result matches the bmm+softmax+bmm
        // path to f64 round-off (softmax is reassociated; MHA parity is tolerance).
        let head_out = ft_kernel_cpu::sdpa_forward_f64(
            &q_heads,
            &k_heads,
            &v_heads,
            batch_heads,
            seq_len,
            seq_len,
            self.head_dim,
            self.head_dim,
            self.scale,
            false,
        );
        let concat = Self::concat_attention_heads(
            &head_out,
            batch_size,
            seq_len,
            self.num_heads,
            self.head_dim,
            embed_dim,
        );

        let Some(output_values) = Self::no_grad_f64_projection_values(
            session,
            &self.out_proj,
            &concat,
            batch_tokens,
            embed_dim,
        )?
        else {
            return Ok(None);
        };

        Ok(Some(session.tensor_variable(
            output_values,
            vec![batch_size, seq_len, embed_dim],
            false,
        )?))
    }

    /// Forward with separate query, key, value tensors.
    ///
    /// All inputs have shape `[N, S, E]` (or `[N, T, E]` for key/value).
    pub fn forward_qkv(
        &self,
        session: &mut FrankenTorchSession,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let q_shape = {
            let (_, meta) = session.tensor_values_meta(query)?;
            meta.shape().to_vec()
        };

        if q_shape.len() != 3 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MultiheadAttention expects 3D input [N, S, E]",
                },
            )));
        }

        let batch_size = q_shape[0];
        let seq_len_q = q_shape[1];
        let embed_dim = q_shape[2];

        let k_shape = {
            let (_, meta) = session.tensor_values_meta(key)?;
            meta.shape().to_vec()
        };
        let seq_len_k = k_shape[1];

        // Project Q, K, V: each [N, S, E] -> [N, S, E]
        // Linear expects [batch, features], so reshape [N, S, E] -> [N*S, E]
        let q_flat = session.tensor_reshape(query, vec![batch_size * seq_len_q, embed_dim])?;
        let q_proj = self.q_proj.forward(session, q_flat)?;
        let q = session.tensor_reshape(q_proj, vec![batch_size, seq_len_q, embed_dim])?;

        let self_attention_input = query == key && key == value;
        let k_flat = if self_attention_input {
            q_flat
        } else {
            session.tensor_reshape(key, vec![batch_size * seq_len_k, embed_dim])?
        };
        let k_proj = self.k_proj.forward(session, k_flat)?;
        let k = session.tensor_reshape(k_proj, vec![batch_size, seq_len_k, embed_dim])?;

        let v_flat = if self_attention_input {
            q_flat
        } else {
            session.tensor_reshape(value, vec![batch_size * seq_len_k, embed_dim])?
        };
        let v_proj = self.v_proj.forward(session, v_flat)?;
        let v = session.tensor_reshape(v_proj, vec![batch_size, seq_len_k, embed_dim])?;

        let batch_heads = batch_size * self.num_heads;

        let q_heads = session.tensor_reshape(
            q,
            vec![batch_size, seq_len_q, self.num_heads, self.head_dim],
        )?;
        let q_heads = session.tensor_permute(q_heads, vec![0, 2, 1, 3])?;
        let q_heads =
            session.tensor_reshape(q_heads, vec![batch_heads, seq_len_q, self.head_dim])?;

        let k_heads = session.tensor_reshape(
            k,
            vec![batch_size, seq_len_k, self.num_heads, self.head_dim],
        )?;
        let k_heads = session.tensor_permute(k_heads, vec![0, 2, 1, 3])?;
        let k_heads =
            session.tensor_reshape(k_heads, vec![batch_heads, seq_len_k, self.head_dim])?;

        let v_heads = session.tensor_reshape(
            v,
            vec![batch_size, seq_len_k, self.num_heads, self.head_dim],
        )?;
        let v_heads = session.tensor_permute(v_heads, vec![0, 2, 1, 3])?;
        let v_heads =
            session.tensor_reshape(v_heads, vec![batch_heads, seq_len_k, self.head_dim])?;

        // Attention via the fused (autograd-aware) scaled-dot-product-attention:
        // softmax(Q_h @ K_h^T * scale) @ V_h -> [N * heads, S_q, head_dim]. The
        // grad-f64 fast path is block-row flash attention that NEVER materialises
        // the [N*heads, S_q, S_k] score / softmax tensors on the tape (the manual
        // bmm + softmax + bmm built two of them, each a full-size node + alloc +
        // backward). Forward matches the bmm+softmax+bmm path bit-for-bit (proven
        // by mha_no_grad_self_attention_fast_path_matches_forward_qkv_bits, same
        // sdpa_forward_f64 kernel); the fused backward matches the op-graph
        // gradients to f64 round-off (MHA parity is tolerance).
        let head_out = session.tensor_scaled_dot_product_attention(
            q_heads,
            k_heads,
            v_heads,
            None,
            false,
            Some(self.scale),
        )?;
        let head_out = session.tensor_reshape(
            head_out,
            vec![batch_size, self.num_heads, seq_len_q, self.head_dim],
        )?;
        let concat = session.tensor_permute(head_out, vec![0, 2, 1, 3])?;
        let concat = session.tensor_reshape(concat, vec![batch_size, seq_len_q, embed_dim])?;

        // Output projection: [N*S_q, E] -> Linear -> [N*S_q, E] -> [N, S_q, E]
        let concat_flat =
            session.tensor_reshape(concat, vec![batch_size * seq_len_q, embed_dim])?;
        let out = self.out_proj.forward(session, concat_flat)?;
        session.tensor_reshape(out, vec![batch_size, seq_len_q, embed_dim])
    }
}

impl Module for MultiheadAttention {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if let Some(output) = self.no_grad_f64_self_attention_fast_path(session, input)? {
            return Ok(output);
        }
        self.forward_qkv(session, input, input, input)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        let mut params = self.q_proj.parameters();
        params.extend(self.k_proj.parameters());
        params.extend(self.v_proj.parameters());
        params.extend(self.out_proj.parameters());
        params
    }

    fn named_children(&self) -> Vec<(String, &dyn Module)> {
        vec![
            ("q_proj".to_string(), &self.q_proj as &dyn Module),
            ("k_proj".to_string(), &self.k_proj as &dyn Module),
            ("v_proj".to_string(), &self.v_proj as &dyn Module),
            ("out_proj".to_string(), &self.out_proj as &dyn Module),
        ]
    }
}

/// Softmax module: applies softmax along a specified dimension.
pub struct Softmax {
    dim: usize,
}

impl Softmax {
    /// Create a Softmax module that normalizes along `dim`.
    #[must_use]
    pub fn new(dim: usize) -> Self {
        Self { dim }
    }
}

impl Module for Softmax {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        session.tensor_softmax(input, self.dim)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Softmax2d module: applies softmax over channels at each spatial location.
///
/// Accepts unbatched `[C, H, W]` or batched `[N, C, H, W]` inputs and preserves
/// the input shape.
pub struct Softmax2d;

impl Module for Softmax2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = session.tensor_shape(input)?;
        let dim = match shape.as_slice() {
            [_, _, _] => 0,
            [_, _, _, _] => 1,
            _ => {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "Softmax2d expects 3D [C, H, W] or 4D [N, C, H, W] input",
                    },
                )));
            }
        };
        session.tensor_softmax(input, dim)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

