/// PReLU (Parametric ReLU) activation module.
///
/// `f(x) = max(0, x) + a * min(0, x)` where `a` is a learnable parameter.
/// When `num_parameters > 1`, a separate slope is learned per channel.
pub struct PReLU {
    weight: TensorNodeId,
    num_parameters: usize,
}

impl PReLU {
    /// Create a PReLU with the given number of parameters and initial slope.
    ///
    /// `num_parameters = 1`: single learnable slope for all channels.
    /// `num_parameters = C`: one learnable slope per channel.
    pub fn new(
        session: &mut FrankenTorchSession,
        num_parameters: usize,
        init: f64,
    ) -> Result<Self, AutogradError> {
        let weight =
            session.tensor_variable(vec![init; num_parameters], vec![num_parameters], true)?;
        Ok(Self {
            weight,
            num_parameters,
        })
    }
}

impl Module for PReLU {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // PReLU(x) = x          if x >= 0
        //          = w[c] * x   otherwise
        //
        // where w broadcasts: a single scalar across all positions
        // when num_parameters == 1, or one slope per channel when
        // num_parameters == channels. Composed as
        //
        //     where(x >= 0, x, weight_broadcast * x)
        //
        // through tensor_ge / tensor_mul / tensor_where + a
        // tensor_reshape + tensor_expand chain that lifts `weight`
        // (shape [num_parameters]) to the full input shape. Backward
        // correctness:
        //   d output / d input  for x >= 0:  1     (where x branch)
        //                       for x <  0:  w[c]  (mul backward)
        //   d output / d weight[c]: sum over (b, spatial) of x_i
        //                           where mask_i == 0 in channel c
        //                           (mul backward + expand backward
        //                            sums broadcast dims back to
        //                            weight's original shape).
        // The previous severed-autograd path dropped both the input
        // and the weight gradient.
        let input_shape = session.tensor_shape(input)?;

        // Determine the pre-expand shape for the weight tensor.
        // tensor_expand requires every original dim to be 1 or to
        // already match the target dim. So we lay out
        //   num_parameters == 1                 → [1, 1, ..., 1]
        //   1-D input, num_parameters == len    → [num_parameters]
        //   N-D input, num_parameters == channels → [1, C, 1, ..., 1]
        let weight_pre_expand: Vec<usize> = if self.num_parameters == 1 {
            if input_shape.is_empty() {
                vec![]
            } else {
                vec![1; input_shape.len()]
            }
        } else if input_shape.len() <= 1 {
            // 1-D input with per-element slope; weight shape must be
            // [num_parameters] and match the input length.
            if input_shape.first().copied().unwrap_or(0) != self.num_parameters {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "PReLU num_parameters must match input length for 1-D input",
                    },
                )));
            }
            vec![self.num_parameters]
        } else {
            // 2+D input: per-channel slope along dim 1.
            if input_shape[1] != self.num_parameters {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "PReLU num_parameters must match channel count",
                    },
                )));
            }
            let mut shape = vec![1usize; input_shape.len()];
            shape[1] = self.num_parameters;
            shape
        };

        let weight_reshaped = if weight_pre_expand == session.tensor_shape(self.weight)? {
            self.weight
        } else {
            session.tensor_reshape(self.weight, weight_pre_expand)?
        };
        let weight_broadcast = if session.tensor_shape(weight_reshaped)? == input_shape {
            weight_reshaped
        } else {
            session.tensor_expand(weight_reshaped, input_shape.clone())?
        };
        let neg_branch = session.tensor_mul(weight_broadcast, input)?;
        let zeros = session.full(input_shape, 0.0, false)?;
        let mask = session.tensor_ge(input, zeros)?;
        session.tensor_where(mask, input, neg_branch)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        vec![self.weight]
    }
}

/// CELU (Continuously Differentiable ELU) activation module.
///
/// `f(x) = max(0, x) + min(0, alpha * (exp(x/alpha) - 1))`
///
/// Unlike standard ELU, CELU is continuously differentiable everywhere.
pub struct CELU {
    alpha: f64,
}

impl CELU {
    /// Create a CELU module with the given alpha.
    #[must_use]
    pub fn new(alpha: f64) -> Self {
        Self { alpha }
    }
}

impl Module for CELU {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose CELU through autograd primitives so the backward
        // pass actually flows through the input. The previous body
        // extracted tensor_values and rebuilt a requires_grad=false
        // leaf, severing the tape — same severed-autograd pattern
        // recently fixed for SELU / Threshold / Hardtanh / Unfold /
        // Fold and the index_* / scatter_* family.
        //
        // CELU(x) = max(0, x) + min(0, alpha * (exp(x/alpha) - 1))
        // is equivalent to
        //     where(x >= 0, x, alpha * (exp(x/alpha) - 1))
        // which composes through tensor_where, tensor_div / tensor_mul
        // by a constant alpha tensor, tensor_exp, and tensor_sub —
        // all autograd-aware.
        //
        // Backward correctness (chain rule through the composition):
        //   x >= 0: grad_x = grad_out * 1 (via the `x` branch of where)
        //                    + grad_out * 0 * d(neg)/dx (the neg branch
        //                                                is masked out)
        //                  = grad_out                        ← analytic
        //   x <  0: grad_x = grad_out * 0           (`x` branch masked)
        //                    + grad_out * 1 * (alpha * (1/alpha) *
        //                                      exp(x/alpha))
        //                  = grad_out * exp(x/alpha)         ← analytic
        // The continuity at x=0 is preserved because both branches
        // give the same derivative there.
        if self.alpha == 0.0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "CELU: alpha must be non-zero",
                },
            )));
        }
        let input_shape = session.tensor_shape(input)?;
        let alpha_tensor = session.full(input_shape.clone(), self.alpha, false)?;
        let scaled = session.tensor_div(input, alpha_tensor)?;
        let exp_scaled = session.tensor_exp(scaled)?;
        let ones = session.full(input_shape.clone(), 1.0, false)?;
        let exp_minus_one = session.tensor_sub(exp_scaled, ones)?;
        let alpha_factor = session.full(input_shape.clone(), self.alpha, false)?;
        let neg_branch = session.tensor_mul(alpha_factor, exp_minus_one)?;
        let zeros = session.full(input_shape, 0.0, false)?;
        let mask = session.tensor_ge(input, zeros)?;
        session.tensor_where(mask, input, neg_branch)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// GLU (Gated Linear Unit) activation module.
///
/// Splits the input tensor along `dim` into two halves `a` and `b`,
/// then computes `a * sigmoid(b)`.
///
/// Input size along `dim` must be even.
pub struct GLU {
    dim: usize,
}

impl GLU {
    /// Create a GLU module that splits along the given dimension.
    #[must_use]
    pub fn new(dim: usize) -> Self {
        Self { dim }
    }
}

impl Module for GLU {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = session.tensor_shape(input)?;
        let dim = self.dim;

        if dim >= input_shape.len() {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GLU: dim out of range",
                },
            )));
        }

        let dim_size = input_shape[dim];
        if dim_size % 2 != 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GLU: input size along dim must be even",
                },
            )));
        }

        let half = dim_size / 2;
        // Split: narrow along dim for first half and second half
        let a = session.tensor_narrow(input, dim, 0, half)?;
        let b = session.tensor_narrow(input, dim, half, half)?;
        let b_sig = session.tensor_sigmoid(b)?;
        session.tensor_mul(a, b_sig)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Threshold activation module.
///
/// `f(x) = x if x > threshold, else value`
pub struct Threshold {
    threshold: f64,
    value: f64,
}

impl Threshold {
    /// Create a Threshold module.
    #[must_use]
    pub fn new(threshold: f64, value: f64) -> Self {
        Self { threshold, value }
    }
}

impl Module for Threshold {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = session.tensor_shape(input)?;
        let threshold = session.full(shape.clone(), self.threshold, false)?;
        let mask = session.tensor_gt(input, threshold)?;
        let replacement = session.full(shape, self.value, false)?;
        session.tensor_where(mask, input, replacement)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Scaled Exponential Linear Unit (SELU).
///
/// `f(x) = scale * (max(0,x) + min(0, alpha*(exp(x)-1)))`
/// where scale ≈ 1.0507 and alpha ≈ 1.6733 are fixed constants.
/// Enables self-normalizing neural networks.
pub struct SELU;

impl Module for SELU {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // PyTorch SELU constants (matches torch.nn.functional.selu).
        const ALPHA: f64 = 1.6732632423543772;
        const SCALE: f64 = 1.0507009873554805;

        // Compose SELU through autograd primitives so the backward
        // pass actually flows through the input. The previous
        // implementation read `tensor_values` and rebuilt a fresh
        // leaf with `requires_grad=false`, which severed the tape and
        // silently zeroed gradients for any upstream parameter.
        //
        // SELU(x) = scale * (alpha * elu(x; alpha=1) + (1 - alpha) * relu(x))
        //
        // Verification:
        //   x >= 0:  alpha*x + (1 - alpha)*x = x       → scale * x
        //   x <  0:  alpha*(e^x - 1) + (1 - alpha)*0   → scale * alpha * (e^x - 1)
        //
        // Both match torch.nn.functional.selu's piecewise definition,
        // and tensor_elu / tensor_relu both have full autograd support.
        let shape = session.tensor_shape(input)?;
        let elu_x = session.tensor_elu(input)?;
        let relu_x = session.tensor_relu(input)?;
        let alpha_t = session.full(shape.clone(), ALPHA, false)?;
        let one_minus_alpha_t = session.full(shape.clone(), 1.0 - ALPHA, false)?;
        let scale_t = session.full(shape, SCALE, false)?;
        let alpha_elu = session.tensor_mul(alpha_t, elu_x)?;
        let omalpha_relu = session.tensor_mul(one_minus_alpha_t, relu_x)?;
        let blended = session.tensor_add(alpha_elu, omalpha_relu)?;
        session.tensor_mul(scale_t, blended)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Hard Tanh activation.
///
/// `f(x) = max(min_val, min(max_val, x))`
/// Default: min_val=-1, max_val=1 (clamp to [-1, 1]).
pub struct Hardtanh {
    min_val: f64,
    max_val: f64,
}

impl Hardtanh {
    #[must_use]
    pub fn new(min_val: f64, max_val: f64) -> Self {
        Self { min_val, max_val }
    }
}

impl Default for Hardtanh {
    fn default() -> Self {
        Self::new(-1.0, 1.0)
    }
}

impl Module for Hardtanh {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        session.tensor_clamp(input, self.min_val, self.max_val)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Soft Shrinkage activation.
///
/// `f(x) = x - lambda if x > lambda, x + lambda if x < -lambda, else 0`
pub struct Softshrink {
    lambda: f64,
}

impl Softshrink {
    #[must_use]
    pub fn new(lambda: f64) -> Self {
        Self { lambda }
    }
}

impl Default for Softshrink {
    fn default() -> Self {
        Self::new(0.5)
    }
}

impl Module for Softshrink {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Softshrink(x) = x - λ  if x > λ
        //               = x + λ  if x < -λ
        //               = 0      otherwise
        //
        // Composed as
        //     where(x > λ,
        //           x - λ,
        //           where(x < -λ, x + λ, 0))
        //
        // Backward delivers the analytical adjoint piecewise: 1 in
        // both shifted regions, 0 in the dead-zone — the chain rule
        // through tensor_sub / tensor_add / tensor_where takes care
        // of it without bespoke kernels.
        let shape = session.tensor_shape(input)?;
        let lambda_t = session.full(shape.clone(), self.lambda, false)?;
        let neg_lambda_t = session.full(shape.clone(), -self.lambda, false)?;
        // Positive shift: x - λ
        let pos_branch = session.tensor_sub(input, lambda_t)?;
        // Negative shift: x + λ
        let neg_lambda_factor = session.full(shape.clone(), self.lambda, false)?;
        let neg_branch = session.tensor_add(input, neg_lambda_factor)?;
        let zeros = session.full(shape.clone(), 0.0, false)?;
        // mask_neg = (x < -λ); inner = where(mask_neg, neg_branch, 0)
        let mask_neg = session.tensor_lt(input, neg_lambda_t)?;
        let inner = session.tensor_where(mask_neg, neg_branch, zeros)?;
        // mask_pos = (x > λ); outer = where(mask_pos, pos_branch, inner)
        let lambda_t2 = session.full(shape, self.lambda, false)?;
        let mask_pos = session.tensor_gt(input, lambda_t2)?;
        session.tensor_where(mask_pos, pos_branch, inner)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Hard Shrinkage activation.
///
/// `f(x) = x if |x| > lambda, else 0`
pub struct Hardshrink {
    lambda: f64,
}

impl Hardshrink {
    #[must_use]
    pub fn new(lambda: f64) -> Self {
        Self { lambda }
    }
}

impl Default for Hardshrink {
    fn default() -> Self {
        Self::new(0.5)
    }
}

impl Module for Hardshrink {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Hardshrink(x) = x if |x| > λ else 0.
        // Compose through tensor_abs + tensor_gt + tensor_where.
        // Backward is automatically piecewise-constant: 1 in the
        // |x| > λ region, 0 elsewhere — matching the analytical
        // adjoint of this piecewise-linear activation.
        let shape = session.tensor_shape(input)?;
        let abs_x = session.tensor_abs(input)?;
        let lambda_t = session.full(shape.clone(), self.lambda, false)?;
        let mask = session.tensor_gt(abs_x, lambda_t)?;
        let zeros = session.full(shape, 0.0, false)?;
        session.tensor_where(mask, input, zeros)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Tanh Shrinkage activation.
///
/// `f(x) = x - tanh(x)`
pub struct Tanhshrink;

impl Module for Tanhshrink {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Tanhshrink(x) = x - tanh(x).
        // tensor_sub and tensor_tanh both have backward kernels, so
        // the chain rule delivers d/dx Tanhshrink(x) = 1 - sech^2(x)
        // automatically. Replaces the previous severed-autograd path
        // (tensor_values → plain f64 → fresh requires_grad=false leaf).
        let tanh_x = session.tensor_tanh(input)?;
        session.tensor_sub(input, tanh_x)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Softsign activation.
///
/// `f(x) = x / (1 + |x|)`
/// Similar to tanh but slower saturation.
pub struct Softsign;

impl Module for Softsign {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Softsign(x) = x / (1 + |x|). Composing through tensor_abs,
        // tensor_add (with broadcast ones), and tensor_div yields the
        // analytical derivative 1 / (1 + |x|)^2 via the chain rule.
        let shape = session.tensor_shape(input)?;
        let abs_x = session.tensor_abs(input)?;
        let ones = session.full(shape, 1.0, false)?;
        let denom = session.tensor_add(ones, abs_x)?;
        session.tensor_div(input, denom)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Softmin activation module.
///
/// `softmin(x)_i = exp(-x_i) / sum_j exp(-x_j)`
/// Equivalent to `Softmax(-x)`. Applied along `dim`.
pub struct Softmin {
    dim: usize,
}

impl Softmin {
    #[must_use]
    pub fn new(dim: usize) -> Self {
        Self { dim }
    }
}

impl Module for Softmin {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Softmin(x) = Softmax(-x). Replace the previous severed-
        // autograd path (tensor_values → plain f64 negate → fresh
        // leaf) with tensor_neg + tensor_softmax composition.
        let neg_input = session.tensor_neg(input)?;
        session.tensor_softmax(neg_input, self.dim)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Hardswish activation module.
///
/// Equivalent to `torch.nn.Hardswish`.
/// `hardswish(x) = x * relu6(x + 3) / 6`
pub struct Hardswish;

impl Module for Hardswish {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        session.tensor_hardswish(input)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Hardsigmoid activation module.
///
/// Equivalent to `torch.nn.Hardsigmoid`.
/// `hardsigmoid(x) = clamp(x/6 + 0.5, 0, 1)`
pub struct Hardsigmoid;

impl Module for Hardsigmoid {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        session.tensor_hardsigmoid(input)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// LogSigmoid activation module.
///
/// Equivalent to `torch.nn.LogSigmoid`.
/// `log_sigmoid(x) = log(sigmoid(x)) = log(1/(1+exp(-x))) = -softplus(-x)`
pub struct LogSigmoid;

impl Module for LogSigmoid {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let sig = session.tensor_sigmoid(input)?;
        session.tensor_log(sig)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Randomized Leaky ReLU activation module.
///
/// Equivalent to `torch.nn.RReLU(lower, upper)`.
/// During training, the negative slope is sampled uniformly from [lower, upper].
/// During evaluation, uses the midpoint (lower + upper) / 2.
pub struct RReLU {
    lower: f64,
    upper: f64,
    training: std::cell::Cell<bool>,
}

impl RReLU {
    #[must_use]
    pub fn new(lower: f64, upper: f64) -> Self {
        Self {
            lower,
            upper,
            training: std::cell::Cell::new(true),
        }
    }
}

impl Default for RReLU {
    fn default() -> Self {
        Self::new(1.0 / 8.0, 1.0 / 3.0)
    }
}

impl Module for RReLU {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // RReLU(x) = x         if x >= 0
        //          = slope * x otherwise
        // where slope is sampled element-wise from U(lower, upper)
        // during training and is the midpoint of [lower, upper] for
        // deterministic eval-mode replay.
        //
        // Composed as where(x >= 0, x, slope * x) using tensor_ge,
        // tensor_mul (with broadcast `slope` constant), and
        // tensor_where. Backward routes the gradient correctly:
        //   x >= 0: 1
        //   x <  0: realized slope
        if !self.lower.is_finite() || !self.upper.is_finite() || self.lower > self.upper {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "RReLU: lower and upper must be finite with lower <= upper",
                },
            )));
        }

        let slope_t = if self.training.get() {
            let random = session.rand_like(input, false)?;
            let span = session.full_like(input, self.upper - self.lower, false)?;
            let scaled = session.tensor_mul(span, random)?;
            let lower = session.full_like(input, self.lower, false)?;
            session.tensor_add(lower, scaled)?
        } else {
            session.full_like(input, (self.lower + self.upper) / 2.0, false)?
        };
        let neg_branch = session.tensor_mul(slope_t, input)?;
        let zeros = session.zeros_like(input, false)?;
        let mask = session.tensor_ge(input, zeros)?;
        session.tensor_where(mask, input, neg_branch)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }

    fn train(&self, mode: bool) {
        self.training.set(mode);
    }

    fn eval(&self) {
        self.training.set(false);
    }

    fn is_training(&self) -> bool {
        self.training.get()
    }
}

/// Group normalization (Wu & He, 2018).
///
/// Divides the channels into `num_groups` groups and normalizes within each group
/// independently. This is more flexible than BatchNorm (which normalizes across
/// the batch) and LayerNorm (which normalizes across all channels).
///
/// Input shape: `[N, C, *]` where `C` must be divisible by `num_groups` and `*`
/// is zero or more spatial dimensions.
///
/// When `affine` is true (default), learnable `weight` (gamma) and `bias` (beta)
/// parameters of shape `[C]` are applied after normalization.
pub struct GroupNorm {
    num_groups: usize,
    num_channels: usize,
    eps: f64,
    weight: Option<TensorNodeId>,
    bias: Option<TensorNodeId>,
}

impl GroupNorm {
    /// Create a new GroupNorm module.
    ///
    /// * `num_groups` - number of groups to divide channels into
    /// * `num_channels` - expected number of channels (C), must be divisible by num_groups
    /// * `eps` - value added to variance for numerical stability (typically 1e-5)
    /// * `affine` - if true, include learnable weight and bias parameters
    pub fn new(
        session: &mut FrankenTorchSession,
        num_groups: usize,
        num_channels: usize,
        eps: f64,
        affine: bool,
    ) -> Result<Self, AutogradError> {
        if num_groups == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GroupNorm requires num_groups > 0",
                },
            )));
        }
        if num_channels == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GroupNorm requires num_channels > 0",
                },
            )));
        }
        if !num_channels.is_multiple_of(num_groups) {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GroupNorm requires num_channels divisible by num_groups",
                },
            )));
        }

        let (weight, bias) = if affine {
            let w = session.tensor_variable(vec![1.0; num_channels], vec![num_channels], true)?;
            let b = session.tensor_variable(vec![0.0; num_channels], vec![num_channels], true)?;
            (Some(w), Some(b))
        } else {
            (None, None)
        };

        Ok(Self {
            num_groups,
            num_channels,
            eps,
            weight,
            bias,
        })
    }
}

impl Module for GroupNorm {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() < 2 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GroupNorm input must have at least 2 dimensions [N, C, ...]",
                },
            )));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];

        if channels != self.num_channels {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "GroupNorm input channels do not match num_channels",
                },
            )));
        }

        let channels_per_group = channels / self.num_groups;
        // Compute spatial size (product of dims after N, C)
        let spatial = if input_shape.len() > 2 {
            checked_shape_numel(&input_shape[2..], "GroupNorm spatial shape overflow")?
        } else {
            1
        };
        let group_numel =
            checked_mul(channels_per_group, spatial, "GroupNorm group size overflow")?;

        // Reshape to [N, num_groups, channels_per_group * spatial] for per-group normalization
        let reshaped =
            session.tensor_reshape(input, vec![batch_size, self.num_groups, group_numel])?;

        // Compute mean per group: mean_dim along dim=2 -> [N, num_groups]
        let mean = session.tensor_mean_dim(reshaped, 2)?;
        // Expand mean back: [N, num_groups] -> [N, num_groups, 1] -> [N, num_groups, group_numel]
        let mean_us = session.tensor_unsqueeze(mean, 2)?;
        let mean_exp =
            session.tensor_expand(mean_us, vec![batch_size, self.num_groups, group_numel])?;

        // diff = x - mean
        let diff = session.tensor_sub(reshaped, mean_exp)?;

        // Variance per group: mean(diff^2, dim=2) -> [N, num_groups]
        let diff_sq = session.tensor_mul(diff, diff)?;
        let var = session.tensor_mean_dim(diff_sq, 2)?;
        let var_us = session.tensor_unsqueeze(var, 2)?;
        let var_exp =
            session.tensor_expand(var_us, vec![batch_size, self.num_groups, group_numel])?;

        // std = sqrt(var + eps)
        let eps_t = session.full(
            vec![batch_size, self.num_groups, group_numel],
            self.eps,
            false,
        )?;
        let var_eps = session.tensor_add(var_exp, eps_t)?;
        let std = session.tensor_sqrt(var_eps)?;

        // normalized = diff / std
        let normalized = session.tensor_div(diff, std)?;

        // Reshape back to original input shape
        let normalized_orig = session.tensor_reshape(normalized, input_shape.clone())?;

        // Apply affine transform if present
        if let (Some(w), Some(b)) = (self.weight, self.bias) {
            // weight and bias have shape [C]. We need to reshape them to be
            // broadcastable with input [N, C, *].
            // Target shape: [1, C, 1, 1, ...] with 1s for each spatial dim
            let mut affine_shape = vec![1usize; input_shape.len()];
            affine_shape[1] = channels;

            let w_reshaped = session.tensor_reshape(w, affine_shape.clone())?;
            let w_expanded = session.tensor_expand(w_reshaped, input_shape.clone())?;
            let b_reshaped = session.tensor_reshape(b, affine_shape)?;
            let b_expanded = session.tensor_expand(b_reshaped, input_shape)?;

            let scaled = session.tensor_mul(w_expanded, normalized_orig)?;
            session.tensor_add(scaled, b_expanded)
        } else {
            Ok(normalized_orig)
        }
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        match (self.weight, self.bias) {
            (Some(w), Some(b)) => vec![w, b],
            _ => Vec::new(),
        }
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        match (self.weight, self.bias) {
            (Some(w), Some(b)) => vec![("weight", w), ("bias", b)],
            _ => Vec::new(),
        }
    }
}

/// Instance normalization for 1D inputs (Ulyanov et al., 2016).
///
/// Normalizes each channel of each sample independently, equivalent to
/// `GroupNorm` with `num_groups = num_channels`.
///
/// Root Mean Square Layer Normalization.
///
/// Equivalent to `torch.nn.RMSNorm(normalized_shape, eps=1e-5)`.
/// Unlike LayerNorm, RMSNorm does not center (subtract mean); it only
/// normalizes by the root mean square: `x * rsqrt(mean(x^2) + eps) * weight`.
///
/// Standard in modern LLM architectures: LLaMA, Mistral, Qwen, DeepSeek.
pub struct RMSNorm {
    normalized_shape: Vec<usize>,
    eps: f64,
    weight: TensorNodeId,
}

impl RMSNorm {
    /// Create a new RMSNorm module.
    ///
    /// `normalized_shape` is the shape of the last dimensions to normalize over.
    /// For a typical LLM with hidden_size=D, use `vec![D]`.
    pub fn new(
        session: &mut FrankenTorchSession,
        normalized_shape: Vec<usize>,
        eps: f64,
    ) -> Result<Self, AutogradError> {
        let total = checked_shape_numel(
            &normalized_shape,
            "RMSNorm normalized_shape volume overflow",
        )?;
        let weight = session.tensor_variable(vec![1.0; total], normalized_shape.clone(), true)?;
        Ok(Self {
            normalized_shape,
            eps,
            weight,
        })
    }

    /// Access the weight parameter.
    #[must_use]
    pub fn weight(&self) -> TensorNodeId {
        self.weight
    }
}

impl Module for RMSNorm {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = session.tensor_shape(input)?;
        let norm_dims = checked_shape_numel(
            &self.normalized_shape,
            "RMSNorm normalized_shape volume overflow",
        )?;
        let ndim = input_shape.len();
        let norm_ndim = self.normalized_shape.len();

        if ndim < norm_ndim {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "RMSNorm: input has fewer dimensions than normalized_shape",
                },
            )));
        }

        // Check trailing dimensions match
        for (i, &ns) in self.normalized_shape.iter().enumerate() {
            if input_shape[ndim - norm_ndim + i] != ns {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "RMSNorm: input trailing dims don't match normalized_shape",
                    },
                )));
            }
        }

        if norm_dims == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "RMSNorm normalized_shape must not contain zero dimensions",
                },
            )));
        }

        let batch_dims = if ndim == norm_ndim {
            1
        } else {
            checked_shape_numel(
                &input_shape[..ndim - norm_ndim],
                "RMSNorm batch shape overflow",
            )?
        };

        // Compose through autograd-aware primitives so gradients
        // flow to both input and the weight parameter. Tracked under
        // frankentorch-krf2. Previously this body extracted values
        // and rebuilt a requires_grad=false leaf — silently severing
        // autograd through every RMSNorm layer (used in LLaMA /
        // Mistral / most modern transformer architectures).
        //
        // Math: y = (x / sqrt(mean(x^2) + eps)) * weight
        // Compute via:
        //   x_flat   = reshape(x, [batch_dims, norm_dims])
        //   sq       = x_flat * x_flat
        //   mean_sq  = mean(sq, dim=1)               [batch_dims]
        //   var_eps  = mean_sq + eps
        //   rms      = sqrt(var_eps)                 [batch_dims]
        //   rms_b    = expand(unsqueeze(rms, 1), [batch_dims, norm_dims])
        //   normed   = x_flat / rms_b
        //   weight_flat = reshape(weight, [norm_dims])
        //   weight_b = expand(unsqueeze(weight_flat, 0), [batch_dims, norm_dims])
        //   y_flat   = normed * weight_b
        //   y        = reshape(y_flat, input_shape)
        let x_flat = session.tensor_reshape(input, vec![batch_dims, norm_dims])?;
        let sq = session.tensor_mul(x_flat, x_flat)?;
        let mean_sq = session.tensor_mean_dim(sq, 1)?; // [batch_dims]
        let eps_t = session.full(vec![batch_dims], self.eps, false)?;
        let var_eps = session.tensor_add(mean_sq, eps_t)?;
        let rms = session.tensor_sqrt(var_eps)?;
        let rms_kd = session.tensor_unsqueeze(rms, 1)?;
        let rms_b = session.tensor_expand(rms_kd, vec![batch_dims, norm_dims])?;
        let normed = session.tensor_div(x_flat, rms_b)?;
        let weight_flat = session.tensor_reshape(self.weight, vec![norm_dims])?;
        let weight_kd = session.tensor_unsqueeze(weight_flat, 0)?;
        let weight_b = session.tensor_expand(weight_kd, vec![batch_dims, norm_dims])?;
        let y_flat = session.tensor_mul(normed, weight_b)?;
        session.tensor_reshape(y_flat, input_shape)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        vec![self.weight]
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        vec![("weight", self.weight)]
    }
}

/// Input shape: `[N, C, L]` where `C` must equal `num_features`.
///
/// Widely used in style transfer and generative models where batch statistics
/// are unreliable or undesirable.
pub struct InstanceNorm1d {
    inner: GroupNorm,
}

impl InstanceNorm1d {
    /// Create a new InstanceNorm1d module.
    ///
    /// * `num_features` - number of channels (C)
    /// * `eps` - value added to variance for numerical stability (typically 1e-5)
    /// * `affine` - if true, include learnable weight and bias parameters
    pub fn new(
        session: &mut FrankenTorchSession,
        num_features: usize,
        eps: f64,
        affine: bool,
    ) -> Result<Self, AutogradError> {
        // InstanceNorm = GroupNorm where each channel is its own group
        let inner = GroupNorm::new(session, num_features, num_features, eps, affine)?;
        Ok(Self { inner })
    }
}

impl Module for InstanceNorm1d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.inner.forward(session, input)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        self.inner.parameters()
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        self.inner.named_parameters_own()
    }
}

/// Instance normalization for 2D inputs (4D tensors).
///
/// Normalizes each channel of each sample independently over spatial dimensions,
/// equivalent to `GroupNorm` with `num_groups = num_channels`.
///
/// Input shape: `[N, C, H, W]` where `C` must equal `num_features`.
pub struct InstanceNorm2d {
    inner: GroupNorm,
    num_features: usize,
}

impl InstanceNorm2d {
    /// Create a new InstanceNorm2d module.
    ///
    /// * `num_features` - number of channels (C)
    /// * `eps` - value added to variance for numerical stability (typically 1e-5)
    /// * `affine` - if true, include learnable weight and bias parameters
    pub fn new(
        session: &mut FrankenTorchSession,
        num_features: usize,
        eps: f64,
        affine: bool,
    ) -> Result<Self, AutogradError> {
        let inner = GroupNorm::new(session, num_features, num_features, eps, affine)?;
        Ok(Self {
            inner,
            num_features,
        })
    }
}

impl Module for InstanceNorm2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "InstanceNorm2d expects 4D input [N, C, H, W]",
                },
            )));
        }

        if input_shape[1] != self.num_features {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "input channel dimension does not match num_features",
                },
            )));
        }

        self.inner.forward(session, input)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        self.inner.parameters()
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        self.inner.named_parameters_own()
    }
}

/// Instance normalization for 3D volumetric inputs.
///
/// Normalizes each channel of each sample independently over depth/height/width,
/// equivalent to `GroupNorm` with `num_groups = num_channels`.
///
/// Input shape: `[N, C, D, H, W]` or unbatched `[C, D, H, W]` where `C` must
/// equal `num_features`.
pub struct InstanceNorm3d {
    inner: GroupNorm,
    num_features: usize,
}

impl InstanceNorm3d {
    /// Create a new InstanceNorm3d module.
    ///
    /// * `num_features` - number of channels (C)
    /// * `eps` - value added to variance for numerical stability (typically 1e-5)
    /// * `affine` - if true, include learnable weight and bias parameters
    pub fn new(
        session: &mut FrankenTorchSession,
        num_features: usize,
        eps: f64,
        affine: bool,
    ) -> Result<Self, AutogradError> {
        let inner = GroupNorm::new(session, num_features, num_features, eps, affine)?;
        Ok(Self {
            inner,
            num_features,
        })
    }
}

impl Module for InstanceNorm3d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = session.tensor_shape(input)?;

        match input_shape.as_slice() {
            [c, d, h, w] => {
                if !matches!(c.cmp(&self.num_features), std::cmp::Ordering::Equal) {
                    return Err(incompatible_error(
                        "input channel dimension does not match num_features",
                    ));
                }
                let batched = session.tensor_reshape(input, vec![1, *c, *d, *h, *w])?;
                let normalized = self.inner.forward(session, batched)?;
                session.tensor_reshape(normalized, input_shape)
            }
            [_n, c, _d, _h, _w] => {
                if !matches!(c.cmp(&self.num_features), std::cmp::Ordering::Equal) {
                    return Err(incompatible_error(
                        "input channel dimension does not match num_features",
                    ));
                }
                self.inner.forward(session, input)
            }
            _ => Err(incompatible_error(
                "InstanceNorm3d expects 4D or 5D input ([C, D, H, W] or [N, C, D, H, W])",
            )),
        }
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        self.inner.parameters()
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        self.inner.named_parameters_own()
    }
}

/// 1D max pooling module.
///
/// Input: `[N, C, L]`. Output: `[N, C, L_out]` where `L_out = (L - kernel_size) / stride + 1`.
/// Selects the maximum value within each pooling window.
pub struct MaxPool1d {
    kernel_size: usize,
    stride: usize,
}

impl MaxPool1d {
    /// Create a MaxPool1d module. If stride is 0, it defaults to kernel_size.
    #[must_use]
    pub fn new(kernel_size: usize, stride: usize) -> Self {
        let effective_stride = if stride == 0 { kernel_size } else { stride };
        Self {
            kernel_size,
            stride: effective_stride,
        }
    }
}

impl Module for MaxPool1d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        validate_positive_pooling_dims(
            &[self.kernel_size, self.stride],
            "MaxPool1d kernel_size and stride must be greater than zero",
        )?;

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 3 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool1d expects 3D input [N, C, L]",
                },
            )));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        let l_in = input_shape[2];

        if l_in < self.kernel_size {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool1d input length smaller than kernel_size",
                },
            )));
        }

        let l_out = (l_in - self.kernel_size) / self.stride + 1;

        // For each output position, narrow the input, max over the kernel dimension
        let mut slices = Vec::with_capacity(l_out);
        for l in 0..l_out {
            let start = l * self.stride;
            // narrow(input, dim=2, start, kernel_size) -> [N, C, K]
            let patch = session.tensor_narrow(input, 2, start, self.kernel_size)?;
            // max_dim over dim 2 -> ([N, C], [N, C] indices)
            let (max_vals, _indices) = session.tensor_max_dim(patch, 2)?;
            // unsqueeze -> [N, C, 1]
            let max_us = session.tensor_unsqueeze(max_vals, 2)?;
            slices.push(max_us);
        }

        // cat along dim 2: [N, C, L_out]
        let output = session.tensor_cat(&slices, 2)?;

        debug_assert_eq!(
            {
                let (_, m) = session.tensor_values_meta(output).unwrap();
                m.shape().to_vec()
            },
            vec![batch_size, channels, l_out]
        );

        Ok(output)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// 2D convolution module.
///
/// Applies cross-correlation over an input signal of shape `[N, C_in, H, W]`.
/// Weight shape: `[C_out, C_in, kH, kW]`. Output: `[N, C_out, H_out, W_out]`
/// where `H_out = (H + 2*padding_h - kH) / stride_h + 1` (similarly for W).
pub struct Conv2d {
    weight: TensorNodeId,
    bias: Option<TensorNodeId>,
    in_channels: usize,
    out_channels: usize,
    kernel_h: usize,
    kernel_w: usize,
    stride_h: usize,
    stride_w: usize,
    padding_h: usize,
    padding_w: usize,
}

impl Conv2d {
    /// Create a new Conv2d with Kaiming uniform initialization.
    ///
    /// `kernel_size` is `(kH, kW)`, `stride` is `(sH, sW)`, `padding` is `(pH, pW)`.
    #[allow(clippy::too_many_arguments)]
    pub fn new(
        session: &mut FrankenTorchSession,
        in_channels: usize,
        out_channels: usize,
        kernel_size: (usize, usize),
        stride: (usize, usize),
        padding: (usize, usize),
        use_bias: bool,
    ) -> Result<Self, AutogradError> {
        let (kh, kw) = kernel_size;
        let (sh, sw) = stride;
        let (ph, pw) = padding;

        if in_channels == 0 || out_channels == 0 || kh == 0 || kw == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "Conv2d requires positive in_channels, out_channels, kernel_size",
                },
            )));
        }
        if sh == 0 || sw == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "Conv2d requires stride > 0",
                },
            )));
        }

        // Kaiming uniform: U(-bound, bound) where bound = sqrt(1 / fan_in)
        let kernel_area = checked_mul(kh, kw, "Conv2d kernel size overflow")?;
        let fan_in = checked_mul(in_channels, kernel_area, "Conv2d fan_in overflow")?;
        let bound = 1.0 / (fan_in as f64).sqrt();
        let numel = checked_mul(out_channels, fan_in, "Conv2d weight size overflow")?;

        let w_rand = session.rand(vec![numel], false)?;
        let w_scale = session.full(vec![numel], 2.0 * bound, false)?;
        let w_scaled = session.tensor_mul(w_rand, w_scale)?;
        let w_shift = session.full(vec![numel], bound, false)?;
        let w_shifted = session.tensor_sub(w_scaled, w_shift)?;
        let w_values = session.tensor_values(w_shifted)?;
        let weight =
            session.tensor_variable(w_values, vec![out_channels, in_channels, kh, kw], true)?;

        let bias = if use_bias {
            let b_rand = session.rand(vec![out_channels], false)?;
            let b_scale = session.full(vec![out_channels], 2.0 * bound, false)?;
            let b_scaled = session.tensor_mul(b_rand, b_scale)?;
            let b_shift = session.full(vec![out_channels], bound, false)?;
            let b_shifted = session.tensor_sub(b_scaled, b_shift)?;
            let b_values = session.tensor_values(b_shifted)?;
            Some(session.tensor_variable(b_values, vec![out_channels], true)?)
        } else {
            None
        };

        Ok(Self {
            weight,
            bias,
            in_channels,
            out_channels,
            kernel_h: kh,
            kernel_w: kw,
            stride_h: sh,
            stride_w: sw,
            padding_h: ph,
            padding_w: pw,
        })
    }

    /// Access the weight parameter.
    #[must_use]
    pub fn weight(&self) -> TensorNodeId {
        self.weight
    }

    /// Access the bias parameter.
    #[must_use]
    pub fn bias(&self) -> Option<TensorNodeId> {
        self.bias
    }
}

impl Module for Conv2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "Conv2d expects 4D input [N, C_in, H, W]",
                },
            )));
        }

        let batch_size = input_shape[0];
        let c_in = input_shape[1];
        if c_in != self.in_channels {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "Conv2d input channels do not match in_channels",
                },
            )));
        }

        let h_in = input_shape[2];
        let w_in = input_shape[3];

        // Apply padding if needed
        let padded = if self.padding_h > 0 || self.padding_w > 0 {
            // PyTorch pad convention: innermost dim first -> [W_before, W_after, H_before, H_after]
            session.tensor_pad(
                input,
                &[
                    self.padding_w,
                    self.padding_w,
                    self.padding_h,
                    self.padding_h,
                ],
                0.0,
            )?
        } else {
            input
        };
        let pad_h = checked_mul(self.padding_h, 2, "Conv2d padding height overflow")?;
        let pad_w = checked_mul(self.padding_w, 2, "Conv2d padding width overflow")?;
        let h_padded = checked_add(h_in, pad_h, "Conv2d padded height overflow")?;
        let w_padded = checked_add(w_in, pad_w, "Conv2d padded width overflow")?;

        // Output spatial dimensions
        if h_padded < self.kernel_h || w_padded < self.kernel_w {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "Conv2d input too small for given kernel_size and padding",
                },
            )));
        }
        let h_out = checked_add(
            (h_padded - self.kernel_h) / self.stride_h,
            1,
            "Conv2d output height overflow",
        )?;
        let w_out = checked_add(
            (w_padded - self.kernel_w) / self.stride_w,
            1,
            "Conv2d output width overflow",
        )?;

        // Im2col: extract sliding 2D windows using narrow on dims 2 and 3
        let ck = checked_mul(
            self.in_channels,
            self.kernel_h,
            "Conv2d kernel size overflow",
        )?;
        let ck = checked_mul(ck, self.kernel_w, "Conv2d kernel size overflow")?;
        let patch_count = checked_mul(h_out, w_out, "Conv2d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for hi in 0..h_out {
            let h_start = checked_mul(hi, self.stride_h, "Conv2d row start overflow")?;
            // narrow on dim 2 (height): [N, C_in, kH, w_padded]
            let row_slice = session.tensor_narrow(padded, 2, h_start, self.kernel_h)?;
            for wi in 0..w_out {
                let w_start = checked_mul(wi, self.stride_w, "Conv2d col start overflow")?;
                // narrow on dim 3 (width): [N, C_in, kH, kW]
                let patch = session.tensor_narrow(row_slice, 3, w_start, self.kernel_w)?;
                // reshape to [N, 1, C_in*kH*kW]
                let flat = session.tensor_reshape(patch, vec![batch_size, 1, ck])?;
                patches.push(flat);
            }
        }

        // cat along dim 1: [N, H_out*W_out, C_in*kH*kW]
        let unfolded = session.tensor_cat(&patches, 1)?;

        // Weight: [C_out, C_in, kH, kW] -> [C_out, ck] -> transpose -> [ck, C_out]
        let w_flat = session.tensor_reshape(self.weight, vec![self.out_channels, ck])?;
        let w_t = session.tensor_transpose(w_flat, 0, 1)?;

        // Expand weight for bmm: [N, ck, C_out]
        let w_us = session.tensor_unsqueeze(w_t, 0)?;
        let w_expanded = session.tensor_expand(w_us, vec![batch_size, ck, self.out_channels])?;

        // bmm: [N, H_out*W_out, ck] @ [N, ck, C_out] -> [N, H_out*W_out, C_out]
        let output = session.tensor_bmm(unfolded, w_expanded)?;

        // Transpose to [N, C_out, H_out*W_out], then reshape to [N, C_out, H_out, W_out]
        let output_t = session.tensor_transpose(output, 1, 2)?;
        let output_4d =
            session.tensor_reshape(output_t, vec![batch_size, self.out_channels, h_out, w_out])?;

        // Add bias if present
        match self.bias {
            Some(bias) => {
                // bias: [C_out] -> [1, C_out, 1, 1] -> expand [N, C_out, H_out, W_out]
                let b_rs = session.tensor_reshape(bias, vec![1, self.out_channels, 1, 1])?;
                let b_exp = session
                    .tensor_expand(b_rs, vec![batch_size, self.out_channels, h_out, w_out])?;
                session.tensor_add(output_4d, b_exp)
            }
            None => Ok(output_4d),
        }
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        let mut params = vec![self.weight];
        if let Some(bias) = self.bias {
            params.push(bias);
        }
        params
    }

    fn named_parameters_own(&self) -> Vec<(&'static str, TensorNodeId)> {
        let mut params = vec![("weight", self.weight)];
        if let Some(bias) = self.bias {
            params.push(("bias", bias));
        }
        params
    }
}

/// 2D max pooling module.
///
/// Input: `[N, C, H, W]`. Output: `[N, C, H_out, W_out]` where
/// `H_out = (H - kH) / sH + 1` and `W_out = (W - kW) / sW + 1`.
/// Selects the maximum value within each 2D pooling window.
pub struct MaxPool2d {
    kernel_h: usize,
    kernel_w: usize,
    stride_h: usize,
    stride_w: usize,
    padding_h: usize,
    padding_w: usize,
}

impl MaxPool2d {
    /// Create a MaxPool2d module.
    ///
    /// If stride values are 0, they default to the corresponding kernel size.
    #[must_use]
    pub fn new(kernel_size: (usize, usize), stride: (usize, usize)) -> Self {
        let (kh, kw) = kernel_size;
        let (sh, sw) = stride;
        Self {
            kernel_h: kh,
            kernel_w: kw,
            stride_h: if sh == 0 { kh } else { sh },
            stride_w: if sw == 0 { kw } else { sw },
            padding_h: 0,
            padding_w: 0,
        }
    }

    /// Set symmetric zero-padding (default `(0, 0)`), matching
    /// `torch.nn.MaxPool2d(padding=...)`. Padded cells use `-inf` so they never
    /// win the max. Each padding value must be at most half its kernel size.
    #[must_use]
    pub fn padding(mut self, padding: (usize, usize)) -> Self {
        self.padding_h = padding.0;
        self.padding_w = padding.1;
        self
    }
}

impl Module for MaxPool2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        validate_positive_pooling_dims(
            &[self.kernel_h, self.kernel_w, self.stride_h, self.stride_w],
            "MaxPool2d kernel_size and stride dimensions must be greater than zero",
        )?;

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool2d expects 4D input [N, C, H, W]",
                },
            )));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];

        // Apply -inf padding (so padded cells never win the max) before pooling.
        // The downstream patch loop then operates on the padded tensor with the
        // padded spatial extents.
        let (input, h_in, w_in) = if self.padding_h > 0 || self.padding_w > 0 {
            if self.padding_h * 2 > self.kernel_h || self.padding_w * 2 > self.kernel_w {
                return Err(AutogradError::Dispatch(DispatchError::Key(
                    DispatchKeyError::IncompatibleSet {
                        reason: "MaxPool2d padding should be at most half of kernel_size",
                    },
                )));
            }
            let padded = session.tensor_pad(
                input,
                &[
                    self.padding_w,
                    self.padding_w,
                    self.padding_h,
                    self.padding_h,
                ],
                f64::NEG_INFINITY,
            )?;
            let h_in = checked_add(input_shape[2], 2 * self.padding_h, "MaxPool2d padded height overflow")?;
            let w_in = checked_add(input_shape[3], 2 * self.padding_w, "MaxPool2d padded width overflow")?;
            (padded, h_in, w_in)
        } else {
            (input, input_shape[2], input_shape[3])
        };

        if h_in < self.kernel_h || w_in < self.kernel_w {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool2d input smaller than kernel_size",
                },
            )));
        }

        let h_out = checked_add(
            (h_in - self.kernel_h) / self.stride_h,
            1,
            "MaxPool2d output height overflow",
        )?;
        let w_out = checked_add(
            (w_in - self.kernel_w) / self.stride_w,
            1,
            "MaxPool2d output width overflow",
        )?;

        // Extract 2D patches, flatten spatial+kernel dims, take max
        let nc = checked_mul(batch_size, channels, "MaxPool2d batch channel overflow")?;
        let kk = checked_mul(
            self.kernel_h,
            self.kernel_w,
            "MaxPool2d kernel size overflow",
        )?;

        let patch_count = checked_mul(h_out, w_out, "MaxPool2d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for hi in 0..h_out {
            let h_start = checked_mul(hi, self.stride_h, "MaxPool2d row start overflow")?;
            let row_slice = session.tensor_narrow(input, 2, h_start, self.kernel_h)?;
            for wi in 0..w_out {
                let w_start = checked_mul(wi, self.stride_w, "MaxPool2d col start overflow")?;
                // [N, C, kH, kW]
                let patch = session.tensor_narrow(row_slice, 3, w_start, self.kernel_w)?;
                // reshape to [N*C, kH*kW]
                let flat = session.tensor_reshape(patch, vec![nc, kk])?;
                // max along dim=1 -> ([N*C], _indices)
                let (max_vals, _) = session.tensor_max_dim(flat, 1)?;
                // reshape to [N, C, 1]
                let shaped = session.tensor_reshape(max_vals, vec![batch_size, channels, 1])?;
                patches.push(shaped);
            }
        }

        // cat along dim 2: [N, C, H_out*W_out]
        let pooled = session.tensor_cat(&patches, 2)?;
        // reshape to [N, C, H_out, W_out]
        session.tensor_reshape(pooled, vec![batch_size, channels, h_out, w_out])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Adaptive average pooling for 2D spatial inputs.
///
/// Input: `[N, C, H_in, W_in]`. Output: `[N, C, H_out, W_out]` where `(H_out, W_out)`
/// is the target output size. Computes the kernel size and stride automatically.
pub struct AdaptiveAvgPool2d {
    output_h: usize,
    output_w: usize,
}

impl AdaptiveAvgPool2d {
    /// Create an AdaptiveAvgPool2d targeting the given output spatial size.
    #[must_use]
    pub fn new(output_size: (usize, usize)) -> Self {
        Self {
            output_h: output_size.0,
            output_w: output_size.1,
        }
    }
}

impl Module for AdaptiveAvgPool2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool2d expects 4D input [N, C, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let h_in = input_shape[2];
        let w_in = input_shape[3];

        if self.output_h == 0 || self.output_w == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool2d output size must be > 0",
                },
            )));
        }

        // Special case: output == input means identity
        if self.output_h == h_in && self.output_w == w_in {
            return Ok(input);
        }

        // Collect output patches column by column: for each (oh, ow) compute start/end indices
        // using PyTorch's floor-division formula: start_i = floor(i * input_size / output_size)
        let col_capacity = checked_mul(
            self.output_h,
            self.output_w,
            "AdaptiveAvgPool2d output size overflow",
        )?;
        let mut col_nodes = Vec::with_capacity(col_capacity);

        for oh in 0..self.output_h {
            for ow in 0..self.output_w {
                let oh_next = checked_add(oh, 1, "AdaptiveAvgPool2d output row overflow")?;
                let ow_next = checked_add(ow, 1, "AdaptiveAvgPool2d output col overflow")?;
                let h_start = adaptive_pool_start_index(
                    oh,
                    h_in,
                    self.output_h,
                    "AdaptiveAvgPool2d row start overflow",
                )?;
                let h_end = adaptive_pool_end_index(
                    oh_next,
                    h_in,
                    self.output_h,
                    "AdaptiveAvgPool2d row end overflow",
                    "AdaptiveAvgPool2d row end ceil overflow",
                )?;
                let w_start = adaptive_pool_start_index(
                    ow,
                    w_in,
                    self.output_w,
                    "AdaptiveAvgPool2d col start overflow",
                )?;
                let w_end = adaptive_pool_end_index(
                    ow_next,
                    w_in,
                    self.output_w,
                    "AdaptiveAvgPool2d col end overflow",
                    "AdaptiveAvgPool2d col end ceil overflow",
                )?;

                let kh = h_end - h_start;
                let kw = w_end - w_start;

                // Narrow along H (dim 2), then W (dim 3)
                let h_slice = session.tensor_narrow(input, 2, h_start, kh)?;
                let hw_slice = session.tensor_narrow(h_slice, 3, w_start, kw)?;

                // Reshape to [N, C, kh*kw] and mean over dim 2 → [N, C]
                let kernel_area = checked_mul(kh, kw, "AdaptiveAvgPool2d kernel size overflow")?;
                let flat = session.tensor_reshape(hw_slice, vec![n, c, kernel_area])?;
                let pooled = session.tensor_mean_dim(flat, 2)?;
                // Unsqueeze to [N, C, 1]
                let col = session.tensor_unsqueeze(pooled, 2)?;
                col_nodes.push(col);
            }
        }

        // Cat all columns along dim 2 → [N, C, output_h * output_w]
        let result = session.tensor_cat(&col_nodes, 2)?;

        // Reshape to [N, C, output_h, output_w]
        session.tensor_reshape(result, vec![n, c, self.output_h, self.output_w])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// 2D average pooling module (non-adaptive).
///
/// Input: `[N, C, H, W]`. Output: `[N, C, H_out, W_out]` where
/// `H_out = floor((H + 2*pad_h - kH) / stride_h) + 1`.
///
/// Supports padding, `ceil_mode` (ceiling instead of floor for output size),
/// and `count_include_pad` (include zero-padded elements in average).
pub struct AvgPool2d {
    kernel_h: usize,
    kernel_w: usize,
    stride_h: usize,
    stride_w: usize,
    padding_h: usize,
    padding_w: usize,
    ceil_mode: bool,
    count_include_pad: bool,
}

impl AvgPool2d {
    /// Create an AvgPool2d module.
    ///
    /// If stride values are 0, they default to the corresponding kernel size.
    #[must_use]
    #[allow(clippy::too_many_arguments)]
    pub fn new(
        kernel_size: (usize, usize),
        stride: (usize, usize),
        padding: (usize, usize),
        ceil_mode: bool,
        count_include_pad: bool,
    ) -> Self {
        let (kh, kw) = kernel_size;
        let (sh, sw) = stride;
        Self {
            kernel_h: kh,
            kernel_w: kw,
            stride_h: if sh == 0 { kh } else { sh },
            stride_w: if sw == 0 { kw } else { sw },
            padding_h: padding.0,
            padding_w: padding.1,
            ceil_mode,
            count_include_pad,
        }
    }
}

impl Module for AvgPool2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.kernel_h == 0 || self.kernel_w == 0 || self.stride_h == 0 || self.stride_w == 0 {
            return Err(incompatible_error(
                "AvgPool2d kernel_size and stride dimensions must be greater than zero",
            ));
        }

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool2d expects 4D input [N, C, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let h_in = input_shape[2];
        let w_in = input_shape[3];

        // Apply padding if needed
        let padded = if self.padding_h > 0 || self.padding_w > 0 {
            // tensor_pad uses innermost-first: [w_before, w_after, h_before, h_after]
            session.tensor_pad(
                input,
                &[
                    self.padding_w,
                    self.padding_w,
                    self.padding_h,
                    self.padding_h,
                ],
                0.0,
            )?
        } else {
            input
        };

        let pad_h = checked_mul(self.padding_h, 2, "AvgPool2d padding height overflow")?;
        let pad_w = checked_mul(self.padding_w, 2, "AvgPool2d padding width overflow")?;
        let h_padded = checked_add(h_in, pad_h, "AvgPool2d padded height overflow")?;
        let w_padded = checked_add(w_in, pad_w, "AvgPool2d padded width overflow")?;

        if h_padded < self.kernel_h || w_padded < self.kernel_w {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool2d input too small for given kernel_size and padding",
                },
            )));
        }

        let h_out_base = if self.ceil_mode {
            (h_padded - self.kernel_h).div_ceil(self.stride_h)
        } else {
            (h_padded - self.kernel_h) / self.stride_h
        };
        let w_out_base = if self.ceil_mode {
            (w_padded - self.kernel_w).div_ceil(self.stride_w)
        } else {
            (w_padded - self.kernel_w) / self.stride_w
        };
        let mut h_out = checked_add(h_out_base, 1, "AvgPool2d output height overflow")?;
        if self.ceil_mode && h_out > 0 {
            let last_start =
                checked_mul(h_out - 1, self.stride_h, "AvgPool2d output height overflow")?;
            let input_pad_boundary =
                checked_add(h_in, self.padding_h, "AvgPool2d output height overflow")?;
            if last_start >= input_pad_boundary {
                h_out -= 1;
            }
        }

        let mut w_out = checked_add(w_out_base, 1, "AvgPool2d output width overflow")?;
        if self.ceil_mode && w_out > 0 {
            let last_start =
                checked_mul(w_out - 1, self.stride_w, "AvgPool2d output width overflow")?;
            let input_pad_boundary =
                checked_add(w_in, self.padding_w, "AvgPool2d output width overflow")?;
            if last_start >= input_pad_boundary {
                w_out -= 1;
            }
        }

        let nc = checked_mul(n, c, "AvgPool2d batch channel overflow")?;

        let patch_count = checked_mul(h_out, w_out, "AvgPool2d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for hi in 0..h_out {
            let h_start = checked_mul(hi, self.stride_h, "AvgPool2d row start overflow")?;
            let h_end =
                checked_add(h_start, self.kernel_h, "AvgPool2d row end overflow")?.min(h_padded);
            let kh_actual = h_end - h_start;
            let valid_h_start = h_start.saturating_sub(self.padding_h).min(h_in);
            let valid_h_end = h_end.saturating_sub(self.padding_h).min(h_in);
            let valid_h_len = valid_h_end.saturating_sub(valid_h_start);
            for wi in 0..w_out {
                let w_start = checked_mul(wi, self.stride_w, "AvgPool2d col start overflow")?;
                let w_end = checked_add(w_start, self.kernel_w, "AvgPool2d col end overflow")?
                    .min(w_padded);
                let kw_actual = w_end - w_start;
                let valid_w_start = w_start.saturating_sub(self.padding_w).min(w_in);
                let valid_w_end = w_end.saturating_sub(self.padding_w).min(w_in);
                let valid_w_len = valid_w_end.saturating_sub(valid_w_start);

                let (patch, flat_len) = if self.count_include_pad {
                    let row_slice = session.tensor_narrow(padded, 2, h_start, kh_actual)?;
                    let patch = session.tensor_narrow(row_slice, 3, w_start, kw_actual)?;
                    let flat_len =
                        checked_mul(kh_actual, kw_actual, "AvgPool2d kernel size overflow")?;
                    (patch, flat_len)
                } else {
                    if valid_h_len == 0 || valid_w_len == 0 {
                        return Err(AutogradError::Dispatch(DispatchError::Key(
                            DispatchKeyError::IncompatibleSet {
                                reason: "AvgPool2d pooling window contains no input elements",
                            },
                        )));
                    }
                    let row_slice = session.tensor_narrow(input, 2, valid_h_start, valid_h_len)?;
                    let patch = session.tensor_narrow(row_slice, 3, valid_w_start, valid_w_len)?;
                    let flat_len = checked_mul(
                        valid_h_len,
                        valid_w_len,
                        "AvgPool2d valid kernel size overflow",
                    )?;
                    (patch, flat_len)
                };
                let flat = session.tensor_reshape(patch, vec![nc, flat_len])?;
                let sum = session.tensor_sum_dim(flat, 1)?;
                let divisor = session.full(vec![nc], flat_len as f64, false)?;
                let avg = session.tensor_div(sum, divisor)?;
                let shaped = session.tensor_reshape(avg, vec![n, c, 1])?;
                patches.push(shaped);
            }
        }

        let pooled = session.tensor_cat(&patches, 2)?;
        session.tensor_reshape(pooled, vec![n, c, h_out, w_out])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// 3D average pooling module.
///
/// Input: `[N, C, D, H, W]`. Output: `[N, C, D_out, H_out, W_out]` where
/// output size is `floor((input_size - kernel_size) / stride) + 1`.
pub struct AvgPool3d {
    kernel_d: usize,
    kernel_h: usize,
    kernel_w: usize,
    stride_d: usize,
    stride_h: usize,
    stride_w: usize,
}

impl AvgPool3d {
    /// Create an AvgPool3d module. If stride values are 0, they default to kernel sizes.
    #[must_use]
    pub fn new(kernel_size: (usize, usize, usize), stride: (usize, usize, usize)) -> Self {
        let (kd, kh, kw) = kernel_size;
        let (sd, sh, sw) = stride;
        Self {
            kernel_d: kd,
            kernel_h: kh,
            kernel_w: kw,
            stride_d: if sd == 0 { kd } else { sd },
            stride_h: if sh == 0 { kh } else { sh },
            stride_w: if sw == 0 { kw } else { sw },
        }
    }
}

impl Module for AvgPool3d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        validate_positive_pooling_dims(
            &[
                self.kernel_d,
                self.kernel_h,
                self.kernel_w,
                self.stride_d,
                self.stride_h,
                self.stride_w,
            ],
            "AvgPool3d kernel_size and stride dimensions must be greater than zero",
        )?;

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 5 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool3d expects 5D input [N, C, D, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let d_in = input_shape[2];
        let h_in = input_shape[3];
        let w_in = input_shape[4];

        if d_in < self.kernel_d || h_in < self.kernel_h || w_in < self.kernel_w {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AvgPool3d input smaller than kernel_size",
                },
            )));
        }

        let d_out = checked_add(
            (d_in - self.kernel_d) / self.stride_d,
            1,
            "AvgPool3d output depth overflow",
        )?;
        let h_out = checked_add(
            (h_in - self.kernel_h) / self.stride_h,
            1,
            "AvgPool3d output height overflow",
        )?;
        let w_out = checked_add(
            (w_in - self.kernel_w) / self.stride_w,
            1,
            "AvgPool3d output width overflow",
        )?;
        let nc = checked_mul(n, c, "AvgPool3d batch channel overflow")?;
        let kkk = checked_mul(
            self.kernel_d,
            self.kernel_h,
            "AvgPool3d kernel size overflow",
        )?;
        let kkk = checked_mul(kkk, self.kernel_w, "AvgPool3d kernel size overflow")?;

        let hw_out = checked_mul(h_out, w_out, "AvgPool3d patch count overflow")?;
        let patch_count = checked_mul(d_out, hw_out, "AvgPool3d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for di in 0..d_out {
            let d_start = checked_mul(di, self.stride_d, "AvgPool3d depth start overflow")?;
            let d_slice = session.tensor_narrow(input, 2, d_start, self.kernel_d)?;
            for hi in 0..h_out {
                let h_start = checked_mul(hi, self.stride_h, "AvgPool3d row start overflow")?;
                let h_slice = session.tensor_narrow(d_slice, 3, h_start, self.kernel_h)?;
                for wi in 0..w_out {
                    let w_start = checked_mul(wi, self.stride_w, "AvgPool3d col start overflow")?;
                    let patch = session.tensor_narrow(h_slice, 4, w_start, self.kernel_w)?;
                    // [N, C, kD, kH, kW] -> [N*C, kD*kH*kW]
                    let flat = session.tensor_reshape(patch, vec![nc, kkk])?;
                    let avg = session.tensor_mean_dim(flat, 1)?;
                    let shaped = session.tensor_reshape(avg, vec![n, c, 1])?;
                    patches.push(shaped);
                }
            }
        }

        let pooled = session.tensor_cat(&patches, 2)?;
        session.tensor_reshape(pooled, vec![n, c, d_out, h_out, w_out])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Fractional 2D max pooling with pseudo-random output size.
///
/// Equivalent to `torch.nn.FractionalMaxPool2d`. Uses a pooling ratio to
/// determine output size stochastically. Output size is approximately
/// `floor(input_size * output_ratio)`.
pub struct FractionalMaxPool2d {
    kernel_h: usize,
    kernel_w: usize,
    output_ratio_h: f64,
    output_ratio_w: f64,
}

impl FractionalMaxPool2d {
    #[must_use]
    pub fn new(kernel_size: (usize, usize), output_ratio: (f64, f64)) -> Self {
        Self {
            kernel_h: kernel_size.0,
            kernel_w: kernel_size.1,
            output_ratio_h: output_ratio.0,
            output_ratio_w: output_ratio.1,
        }
    }
}

impl Module for FractionalMaxPool2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.kernel_h == 0 || self.kernel_w == 0 {
            return Err(incompatible_error(
                "FractionalMaxPool2d kernel_size must be > 0",
            ));
        }
        if !(0.0..=1.0).contains(&self.output_ratio_h)
            || !(0.0..=1.0).contains(&self.output_ratio_w)
        {
            return Err(incompatible_error(
                "FractionalMaxPool2d output_ratio must be in (0, 1]",
            ));
        }

        let shape = session.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(incompatible_error(
                "FractionalMaxPool2d expects 4D input [N, C, H, W]",
            ));
        }

        let h_in = shape[2];
        let w_in = shape[3];
        let h_out = ((h_in as f64) * self.output_ratio_h).floor().max(1.0) as usize;
        let w_out = ((w_in as f64) * self.output_ratio_w).floor().max(1.0) as usize;

        let (out, _indices) = session.tensor_adaptive_max_pool2d(input, (h_out, w_out))?;
        Ok(out)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Fractional 3D max pooling with pseudo-random output size.
///
/// Equivalent to `torch.nn.FractionalMaxPool3d`.
pub struct FractionalMaxPool3d {
    kernel_d: usize,
    kernel_h: usize,
    kernel_w: usize,
    output_ratio_d: f64,
    output_ratio_h: f64,
    output_ratio_w: f64,
}

impl FractionalMaxPool3d {
    #[must_use]
    pub fn new(kernel_size: (usize, usize, usize), output_ratio: (f64, f64, f64)) -> Self {
        Self {
            kernel_d: kernel_size.0,
            kernel_h: kernel_size.1,
            kernel_w: kernel_size.2,
            output_ratio_d: output_ratio.0,
            output_ratio_h: output_ratio.1,
            output_ratio_w: output_ratio.2,
        }
    }
}

impl Module for FractionalMaxPool3d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.kernel_d == 0 || self.kernel_h == 0 || self.kernel_w == 0 {
            return Err(incompatible_error(
                "FractionalMaxPool3d kernel_size must be > 0",
            ));
        }
        if !(0.0..=1.0).contains(&self.output_ratio_d)
            || !(0.0..=1.0).contains(&self.output_ratio_h)
            || !(0.0..=1.0).contains(&self.output_ratio_w)
        {
            return Err(incompatible_error(
                "FractionalMaxPool3d output_ratio must be in (0, 1]",
            ));
        }

        let shape = session.tensor_shape(input)?;
        if shape.len() != 5 {
            return Err(incompatible_error(
                "FractionalMaxPool3d expects 5D input [N, C, D, H, W]",
            ));
        }

        let d_in = shape[2];
        let h_in = shape[3];
        let w_in = shape[4];
        let d_out = ((d_in as f64) * self.output_ratio_d).floor().max(1.0) as usize;
        let h_out = ((h_in as f64) * self.output_ratio_h).floor().max(1.0) as usize;
        let w_out = ((w_in as f64) * self.output_ratio_w).floor().max(1.0) as usize;

        let (out, _indices) = session.tensor_adaptive_max_pool3d(input, (d_out, h_out, w_out))?;
        Ok(out)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// 3D max pooling module.
///
/// Input: `[N, C, D, H, W]`. Output: `[N, C, D_out, H_out, W_out]` where
/// output size is `floor((input_size - kernel_size) / stride) + 1`.
pub struct MaxPool3d {
    kernel_d: usize,
    kernel_h: usize,
    kernel_w: usize,
    stride_d: usize,
    stride_h: usize,
    stride_w: usize,
}

impl MaxPool3d {
    /// Create a MaxPool3d module. If stride values are 0, they default to kernel sizes.
    #[must_use]
    pub fn new(kernel_size: (usize, usize, usize), stride: (usize, usize, usize)) -> Self {
        let (kd, kh, kw) = kernel_size;
        let (sd, sh, sw) = stride;
        Self {
            kernel_d: kd,
            kernel_h: kh,
            kernel_w: kw,
            stride_d: if sd == 0 { kd } else { sd },
            stride_h: if sh == 0 { kh } else { sh },
            stride_w: if sw == 0 { kw } else { sw },
        }
    }
}

impl Module for MaxPool3d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        validate_positive_pooling_dims(
            &[
                self.kernel_d,
                self.kernel_h,
                self.kernel_w,
                self.stride_d,
                self.stride_h,
                self.stride_w,
            ],
            "MaxPool3d kernel_size and stride dimensions must be greater than zero",
        )?;

        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 5 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool3d expects 5D input [N, C, D, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let d_in = input_shape[2];
        let h_in = input_shape[3];
        let w_in = input_shape[4];

        if d_in < self.kernel_d || h_in < self.kernel_h || w_in < self.kernel_w {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "MaxPool3d input smaller than kernel_size",
                },
            )));
        }

        let d_out = checked_add(
            (d_in - self.kernel_d) / self.stride_d,
            1,
            "MaxPool3d output depth overflow",
        )?;
        let h_out = checked_add(
            (h_in - self.kernel_h) / self.stride_h,
            1,
            "MaxPool3d output height overflow",
        )?;
        let w_out = checked_add(
            (w_in - self.kernel_w) / self.stride_w,
            1,
            "MaxPool3d output width overflow",
        )?;
        let nc = checked_mul(n, c, "MaxPool3d batch channel overflow")?;
        let kkk = checked_mul(
            self.kernel_d,
            self.kernel_h,
            "MaxPool3d kernel size overflow",
        )?;
        let kkk = checked_mul(kkk, self.kernel_w, "MaxPool3d kernel size overflow")?;

        let hw_out = checked_mul(h_out, w_out, "MaxPool3d patch count overflow")?;
        let patch_count = checked_mul(d_out, hw_out, "MaxPool3d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for di in 0..d_out {
            let d_start = checked_mul(di, self.stride_d, "MaxPool3d depth start overflow")?;
            let d_slice = session.tensor_narrow(input, 2, d_start, self.kernel_d)?;
            for hi in 0..h_out {
                let h_start = checked_mul(hi, self.stride_h, "MaxPool3d row start overflow")?;
                let h_slice = session.tensor_narrow(d_slice, 3, h_start, self.kernel_h)?;
                for wi in 0..w_out {
                    let w_start = checked_mul(wi, self.stride_w, "MaxPool3d col start overflow")?;
                    let patch = session.tensor_narrow(h_slice, 4, w_start, self.kernel_w)?;
                    let flat = session.tensor_reshape(patch, vec![nc, kkk])?;
                    let (max_vals, _) = session.tensor_max_dim(flat, 1)?;
                    let shaped = session.tensor_reshape(max_vals, vec![n, c, 1])?;
                    patches.push(shaped);
                }
            }
        }

        let pooled = session.tensor_cat(&patches, 2)?;
        session.tensor_reshape(pooled, vec![n, c, d_out, h_out, w_out])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Adaptive average pooling for 1D inputs.
///
/// Input: `[N, C, L]`. Output: `[N, C, L_out]` where `L_out` is the target output size.
pub struct AdaptiveAvgPool1d {
    output_size: usize,
}

impl AdaptiveAvgPool1d {
    /// Create an AdaptiveAvgPool1d targeting the given output length.
    #[must_use]
    pub fn new(output_size: usize) -> Self {
        Self { output_size }
    }
}

impl Module for AdaptiveAvgPool1d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 3 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool1d expects 3D input [N, C, L]",
                },
            )));
        }

        let _n = input_shape[0];
        let _c = input_shape[1];
        let l_in = input_shape[2];

        if self.output_size == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool1d output size must be > 0",
                },
            )));
        }

        if self.output_size == l_in {
            return Ok(input);
        }

        let mut slices = Vec::with_capacity(self.output_size);
        for i in 0..self.output_size {
            let i_next = checked_add(i, 1, "AdaptiveAvgPool1d output index overflow")?;
            let start = adaptive_pool_start_index(
                i,
                l_in,
                self.output_size,
                "AdaptiveAvgPool1d start overflow",
            )?;
            let end = adaptive_pool_end_index(
                i_next,
                l_in,
                self.output_size,
                "AdaptiveAvgPool1d end overflow",
                "AdaptiveAvgPool1d end ceil overflow",
            )?;
            let k = end - start;
            let patch = session.tensor_narrow(input, 2, start, k)?;
            let avg = session.tensor_mean_dim(patch, 2)?;
            let col = session.tensor_unsqueeze(avg, 2)?;
            slices.push(col);
        }

        session.tensor_cat(&slices, 2)
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

/// Adaptive average pooling for 3D spatial inputs.
///
/// Input: `[N, C, D, H, W]`. Output: `[N, C, D_out, H_out, W_out]` where
/// `(D_out, H_out, W_out)` is the target output size.
pub struct AdaptiveAvgPool3d {
    output_d: usize,
    output_h: usize,
    output_w: usize,
}

impl AdaptiveAvgPool3d {
    /// Create an AdaptiveAvgPool3d targeting the given output spatial size.
    #[must_use]
    pub fn new(output_size: (usize, usize, usize)) -> Self {
        Self {
            output_d: output_size.0,
            output_h: output_size.1,
            output_w: output_size.2,
        }
    }
}

impl Module for AdaptiveAvgPool3d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 5 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool3d expects 5D input [N, C, D, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let d_in = input_shape[2];
        let h_in = input_shape[3];
        let w_in = input_shape[4];

        if self.output_d == 0 || self.output_h == 0 || self.output_w == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveAvgPool3d output size must be > 0",
                },
            )));
        }

        if self.output_d == d_in && self.output_h == h_in && self.output_w == w_in {
            return Ok(input);
        }

        let nc = checked_mul(n, c, "AdaptiveAvgPool3d batch channel overflow")?;
        let spatial_out = checked_mul(
            self.output_d,
            checked_mul(
                self.output_h,
                self.output_w,
                "AdaptiveAvgPool3d output size overflow",
            )?,
            "AdaptiveAvgPool3d output size overflow",
        )?;
        let mut patches = Vec::with_capacity(spatial_out);

        for od in 0..self.output_d {
            let od_next = checked_add(od, 1, "AdaptiveAvgPool3d output depth overflow")?;
            let d_start = adaptive_pool_start_index(
                od,
                d_in,
                self.output_d,
                "AdaptiveAvgPool3d depth start overflow",
            )?;
            let d_end = adaptive_pool_end_index(
                od_next,
                d_in,
                self.output_d,
                "AdaptiveAvgPool3d depth end overflow",
                "AdaptiveAvgPool3d depth end ceil overflow",
            )?;
            let kd = d_end - d_start;
            let d_slice = session.tensor_narrow(input, 2, d_start, kd)?;

            for oh in 0..self.output_h {
                let oh_next = checked_add(oh, 1, "AdaptiveAvgPool3d output row overflow")?;
                let h_start = adaptive_pool_start_index(
                    oh,
                    h_in,
                    self.output_h,
                    "AdaptiveAvgPool3d row start overflow",
                )?;
                let h_end = adaptive_pool_end_index(
                    oh_next,
                    h_in,
                    self.output_h,
                    "AdaptiveAvgPool3d row end overflow",
                    "AdaptiveAvgPool3d row end ceil overflow",
                )?;
                let kh = h_end - h_start;
                let h_slice = session.tensor_narrow(d_slice, 3, h_start, kh)?;

                for ow in 0..self.output_w {
                    let ow_next = checked_add(ow, 1, "AdaptiveAvgPool3d output col overflow")?;
                    let w_start = adaptive_pool_start_index(
                        ow,
                        w_in,
                        self.output_w,
                        "AdaptiveAvgPool3d col start overflow",
                    )?;
                    let w_end = adaptive_pool_end_index(
                        ow_next,
                        w_in,
                        self.output_w,
                        "AdaptiveAvgPool3d col end overflow",
                        "AdaptiveAvgPool3d col end ceil overflow",
                    )?;
                    let kw = w_end - w_start;
                    let patch = session.tensor_narrow(h_slice, 4, w_start, kw)?;

                    let kernel_plane =
                        checked_mul(kd, kh, "AdaptiveAvgPool3d kernel size overflow")?;
                    let kernel_volume =
                        checked_mul(kernel_plane, kw, "AdaptiveAvgPool3d kernel size overflow")?;
                    let flat = session.tensor_reshape(patch, vec![nc, kernel_volume])?;
                    let avg = session.tensor_mean_dim(flat, 1)?;
                    let shaped = session.tensor_reshape(avg, vec![n, c, 1])?;
                    patches.push(shaped);
                }
            }
        }

        let pooled = session.tensor_cat(&patches, 2)?;
        session.tensor_reshape(
            pooled,
            vec![n, c, self.output_d, self.output_h, self.output_w],
        )
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

