/// Adaptive max pooling for 2D spatial inputs.
///
/// Input: `[N, C, H, W]`. Output: `[N, C, H_out, W_out]`.
pub struct AdaptiveMaxPool2d {
    output_h: usize,
    output_w: usize,
}

impl AdaptiveMaxPool2d {
    /// Create an AdaptiveMaxPool2d targeting the given output spatial size.
    #[must_use]
    pub fn new(output_size: (usize, usize)) -> Self {
        Self {
            output_h: output_size.0,
            output_w: output_size.1,
        }
    }
}

impl Module for AdaptiveMaxPool2d {
    fn forward(
        &self,
        session: &mut FrankenTorchSession,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = { session.tensor_shape(input)? };

        if input_shape.len() != 4 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveMaxPool2d expects 4D input [N, C, H, W]",
                },
            )));
        }

        let n = input_shape[0];
        let c = input_shape[1];
        let h_in = input_shape[2];
        let w_in = input_shape[3];

        if self.output_h == 0 || self.output_w == 0 {
            return Err(AutogradError::Dispatch(DispatchError::Key(
                DispatchKeyError::IncompatibleSet {
                    reason: "AdaptiveMaxPool2d output size must be > 0",
                },
            )));
        }

        let nc = checked_mul(n, c, "AdaptiveMaxPool2d batch channel overflow")?;
        let spatial_out = checked_mul(
            self.output_h,
            self.output_w,
            "AdaptiveMaxPool2d output size overflow",
        )?;
        let mut patches = Vec::with_capacity(spatial_out);

        for oh in 0..self.output_h {
            let oh_next = checked_add(oh, 1, "AdaptiveMaxPool2d output row overflow")?;
            let h_start = adaptive_pool_start_index(
                oh,
                h_in,
                self.output_h,
                "AdaptiveMaxPool2d row start overflow",
            )?;
            let h_end = adaptive_pool_end_index(
                oh_next,
                h_in,
                self.output_h,
                "AdaptiveMaxPool2d row end overflow",
                "AdaptiveMaxPool2d row end ceil overflow",
            )?;
            let kh = h_end - h_start;
            let h_slice = session.tensor_narrow(input, 2, h_start, kh)?;

            for ow in 0..self.output_w {
                let ow_next = checked_add(ow, 1, "AdaptiveMaxPool2d output col overflow")?;
                let w_start = adaptive_pool_start_index(
                    ow,
                    w_in,
                    self.output_w,
                    "AdaptiveMaxPool2d col start overflow",
                )?;
                let w_end = adaptive_pool_end_index(
                    ow_next,
                    w_in,
                    self.output_w,
                    "AdaptiveMaxPool2d col end overflow",
                    "AdaptiveMaxPool2d col end ceil overflow",
                )?;
                let kw = w_end - w_start;
                let patch = session.tensor_narrow(h_slice, 3, w_start, kw)?;

                let kernel_area = checked_mul(kh, kw, "AdaptiveMaxPool2d kernel size overflow")?;
                let flat = session.tensor_reshape(patch, vec![nc, kernel_area])?;
                let (max_vals, _) = session.tensor_max_dim(flat, 1)?;
                let shaped = session.tensor_reshape(max_vals, vec![n, c, 1])?;
                patches.push(shaped);
            }
        }

        let pooled = session.tensor_cat(&patches, 2)?;
        session.tensor_reshape(pooled, vec![n, c, self.output_h, self.output_w])
    }

    fn parameters(&self) -> Vec<TensorNodeId> {
        Vec::new()
    }
}

