    #[test]
    fn init_orthogonal_preserves_orthonormality() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let t = s.tensor_variable(vec![0.0; 25], vec![5, 5], true).unwrap();
        init_orthogonal_(&mut s, t, 1.0).unwrap();
        let vals = s.tensor_values(t).unwrap();
        // Check Q^T Q ≈ I: dot products of different rows should be ~0
        for i in 0..5 {
            for j in 0..5 {
                let dot: f64 = (0..5).map(|k| vals[i * 5 + k] * vals[j * 5 + k]).sum();
                if i == j {
                    assert!(
                        (dot - 1.0).abs() < 0.1,
                        "diagonal dot({i},{j})={dot}, expected ~1"
                    );
                } else {
                    assert!(
                        dot.abs() < 0.1,
                        "off-diagonal dot({i},{j})={dot}, expected ~0"
                    );
                }
            }
        }
    }

    #[test]
    fn init_orthogonal_wide_matrix_preserves_row_orthonormality() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let t = s.tensor_variable(vec![0.0; 8], vec![2, 4], true).unwrap();
        init_orthogonal_(&mut s, t, 1.0).unwrap();
        let vals = s.tensor_values(t).unwrap();

        for i in 0..2 {
            for j in 0..2 {
                let dot: f64 = (0..4).map(|k| vals[i * 4 + k] * vals[j * 4 + k]).sum();
                if i == j {
                    assert!(
                        (dot - 1.0).abs() < 1e-8,
                        "row norm dot({i},{j})={dot}, expected 1"
                    );
                } else {
                    assert!(dot.abs() < 1e-8, "row dot({i},{j})={dot}, expected 0");
                }
            }
        }

        let tail_norm: f64 = vals[2..4]
            .iter()
            .chain(vals[6..8].iter())
            .map(|v| v * v)
            .sum();
        assert!(
            tail_norm > 1e-12,
            "wide orthogonal_ must not leave the trailing columns zero-padded"
        );
    }

